-- NIST SP 800-53 Rev 5 base controls seed for nist_controls
-- Generated from "NIST 800-53 Controls List.xlsx"
-- Maps each 800-53 family to its primary NIST CSF 2.0 category.
-- Priority is derived from the lowest baseline the control appears in
--   (Low=1 highest priority, Moderate=2, High=3, Privacy=4, none=5).

BEGIN;

-- Wipe any existing rows. CASCADE clears control_recommendations rows that
-- reference them.
TRUNCATE TABLE nist_controls RESTART IDENTITY CASCADE;

INSERT INTO nist_controls
  (control_id, domain, control_name, description,
   nist_csf_function, nist_csf_category, implementation_note, priority, is_active)
VALUES
  ('AC-1', 'Access Control', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] access control policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the access control policy and the associated access controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the access control policy and procedures; and c. Review and update the current access control: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.AA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AC-2', 'Access Control', 'Account Management', 'a. Define and document the types of accounts allowed and specifically prohibited for use within the system; b. Assign account managers; c. Require [Assignment: organization-defined prerequisites and criteria] for group and role membership; d. Specify: 1. Authorized users of the system; 2. Group and role membership; and 3. Access authorizations (i.e., privileges) and [Assignment: organization-defined attributes (as required)] for each account; e. Require approvals by [Assignment: organization-defined personnel or roles] for requests to create accounts; f. Create, enable, modify, disable, and remove accounts in accordance with [Assignment: organization-defined policy, procedures, prerequisites, and criteria]; g. Monitor the use of accounts; h. Notify account managers and [Assignment: organization-defined personnel or roles] within: 1. [Assignment: organization-defined time period] when accounts are no longer required; 2. [Assignment: organization-defined time period] when users are terminated or transferred; and 3. [Assignment: organization-defined time period] when system usage or need-to-know changes for an individual; i. Authorize access to the system based on: 1. A valid access authorization; 2. Intended system usage; and 3. [Assignment: organization-defined attributes (as required)]; j. Review accounts for compliance with account management requirements [Assignment: organization-defined frequency]; k. Establish and implement a process for changing shared or group account authenticators (if deployed) when individuals are removed from the group; and l. Align account management processes with personnel termination and transfer processes.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-3', 'Access Control', 'Access Enforcement', 'Enforce approved authorizations for logical access to information and system resources in accordance with applicable access control policies.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-4', 'Access Control', 'Information Flow Enforcement', 'Enforce approved authorizations for controlling the flow of information within the system and between connected systems based on [Assignment: organization-defined information flow control policies].', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-5', 'Access Control', 'Separation of Duties', 'a. Identify and document [Assignment: organization-defined duties of individuals requiring separation]; and b. Define system access authorizations to support separation of duties.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-6', 'Access Control', 'Least Privilege', 'Employ the principle of least privilege, allowing only authorized accesses for users (or processes acting on behalf of users) that are necessary to accomplish assigned organizational tasks.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-7', 'Access Control', 'Unsuccessful Logon Attempts', 'a. Enforce a limit of [Assignment: organization-defined number] consecutive invalid logon attempts by a user during a [Assignment: organization-defined time period]; and b. Automatically [Selection (one or more): lock the account or node for an [Assignment: organization-defined time period] ; lock the account or node until released by an administrator; delay next logon prompt per [Assignment: organization-defined delay algorithm] ; notify system administrator; take other [Assignment: organization-defined action] ] when the maximum number of unsuccessful attempts is exceeded.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-8', 'Access Control', 'System Use Notification', 'a. Display [Assignment: organization-defined system use notification message or banner] to users before granting access to the system that provides privacy and security notices consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines and state that: 1. Users are accessing a U.S. Government system; 2. System usage may be monitored, recorded, and subject to audit; 3. Unauthorized use of the system is prohibited and subject to criminal and civil penalties; and 4. Use of the system indicates consent to monitoring and recording; b. Retain the notification message or banner on the screen until users acknowledge the usage conditions and take explicit actions to log on to or further access the system; and c. For publicly accessible systems: 1. Display system use information [Assignment: organization-defined conditions], before granting further access to the publicly accessible system; 2. Display references, if any, to monitoring, recording, or auditing that are consistent with privacy accommodations for such systems that generally prohibit those activities; and 3. Include a description of the authorized uses of the system.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-9', 'Access Control', 'Previous Logon Notification', 'Notify the user, upon successful logon to the system, of the date and time of the last logon.', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-10', 'Access Control', 'Concurrent Session Control', 'Limit the number of concurrent sessions for each [Assignment: organization-defined account and/or account type] to [Assignment: organization-defined number].', 'Protect', 'PR.AA', 'Required for High baseline', 3, true),
  ('AC-11', 'Access Control', 'Device Lock', 'a. Prevent further access to the system by [Selection (one or more): initiating a device lock after [Assignment: organization-defined time period] of inactivity; requiring the user to initiate a device lock before leaving the system unattended]; and b. Retain the device lock until the user reestablishes access using established identification and authentication procedures.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-12', 'Access Control', 'Session Termination', 'Automatically terminate a user session after [Assignment: organization-defined conditions, or trigger events requiring session disconnect].', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-13', 'Access Control', 'Supervision and Review — Access Control', 'Withdrawn', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-14', 'Access Control', 'Permitted Actions Without Identification or Authentication', 'a. Identify [Assignment: organization-defined user actions] that can be performed on the system without identification or authentication consistent with organizational mission and business functions; and b. Document and provide supporting rationale in the security plan for the system, user actions not requiring identification or authentication.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-15', 'Access Control', 'Automated Marking', 'Withdrawn', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-16', 'Access Control', 'Security and Privacy Attributes', 'a. Provide the means to associate [Assignment: organization-defined types of security and privacy attributes] with [Assignment: organization-defined security and privacy attribute values] for information in storage, in process, and/or in transmission; b. Ensure that the attribute associations are made and retained with the information; c. Establish the following permitted security and privacy attributes from the attributes defined in AC-16a for [Assignment: organization-defined systems]: [Assignment: organization-defined security and privacy attributes]; d. Determine the following permitted attribute values or ranges for each of the established attributes: [Assignment: organization-defined attribute values or ranges for established attributes]; e. Audit changes to attributes; and f. Review [Assignment: organization-defined security and privacy attributes] for applicability [Assignment: organization-defined frequency].', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-17', 'Access Control', 'Remote Access', 'a. Establish and document usage restrictions, configuration/connection requirements, and implementation guidance for each type of remote access allowed; and b. Authorize each type of remote access to the system prior to allowing such connections.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-18', 'Access Control', 'Wireless Access', 'a. Establish configuration requirements, connection requirements, and implementation guidance for each type of wireless access; and b. Authorize each type of wireless access to the system prior to allowing such connections.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-19', 'Access Control', 'Access Control for Mobile Devices', 'a. Establish configuration requirements, connection requirements, and implementation guidance for organization-controlled mobile devices, to include when such devices are outside of controlled areas; and b. Authorize the connection of mobile devices to organizational systems.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-20', 'Access Control', 'Use of External Systems', 'a. [Selection (one or more): Establish [Assignment: organization-defined terms and conditions] ; Identify [Assignment: organization-defined controls asserted to be implemented on external systems] ], consistent with the trust relationships established with other organizations owning, operating, and/or maintaining external systems, allowing authorized individuals to: 1. Access the system from external systems; and 2. Process, store, or transmit organization-controlled information using external systems; or b. Prohibit the use of [Assignment: organizationally-defined types of external systems].', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-21', 'Access Control', 'Information Sharing', 'a. Enable authorized users to determine whether access authorizations assigned to a sharing partner match the information’s access and use restrictions for [Assignment: organization-defined information sharing circumstances where user discretion is required]; and b. Employ [Assignment: organization-defined automated mechanisms or manual processes] to assist users in making information sharing and collaboration decisions.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('AC-22', 'Access Control', 'Publicly Accessible Content', 'a. Designate individuals authorized to make information publicly accessible; b. Train authorized individuals to ensure that publicly accessible information does not contain nonpublic information; c. Review the proposed content of information prior to posting onto the publicly accessible system to ensure that nonpublic information is not included; and d. Review the content on the publicly accessible system for nonpublic information [Assignment: organization-defined frequency] and remove such information, if discovered.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('AC-23', 'Access Control', 'Data Mining Protection', 'Employ [Assignment: organization-defined data mining prevention and detection techniques] for [Assignment: organization-defined data storage objects] to detect and protect against unauthorized data mining.', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-24', 'Access Control', 'Access Control Decisions', '[Selection: Establish procedures; Implement mechanisms] to ensure [Assignment: organization-defined access control decisions] are applied to each access request prior to access enforcement.', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AC-25', 'Access Control', 'Reference Monitor', 'Implement a reference monitor for [Assignment: organization-defined access control policies] that is tamperproof, always invoked, and small enough to be subject to analysis and testing, the completeness of which can be assured.', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('AT-1', 'Awareness and Training', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] awareness and training policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the awareness and training policy and the associated awareness and training controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the awareness and training policy and procedures; and c. Review and update the current awareness and training: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.AT', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AT-2', 'Awareness and Training', 'Literacy Training and Awareness', 'a. Provide security and privacy literacy training to system users (including managers, senior executives, and contractors): 1. As part of initial training for new users and [Assignment: organization-defined frequency] thereafter; and 2. When required by system changes or following [Assignment: organization-defined events]; b. Employ the following techniques to increase the security and privacy awareness of system users [Assignment: organization-defined awareness techniques]; c. Update literacy training and awareness content [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and d. Incorporate lessons learned from internal or external security or privacy incidents into literacy training and awareness techniques.', 'Protect', 'PR.AT', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AT-3', 'Awareness and Training', 'Role-based Training', 'a. Provide role-based security and privacy training to personnel with the following roles and responsibilities: [Assignment: organization-defined roles and responsibilities]: 1. Before authorizing access to the system, information, or performing assigned duties, and [Assignment: organization-defined frequency] thereafter; and 2. When required by system changes; b. Update role-based training content [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and c. Incorporate lessons learned from internal or external security or privacy incidents into role-based training.', 'Protect', 'PR.AT', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AT-4', 'Awareness and Training', 'Training Records', 'a. Document and monitor information security and privacy training activities, including security and privacy awareness training and specific role-based security and privacy training; and b. Retain individual training records for [Assignment: organization-defined time period].', 'Protect', 'PR.AT', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AT-5', 'Awareness and Training', 'Contacts with Security Groups and Associations', 'Withdrawn', 'Protect', 'PR.AT', 'No baseline assignment', 5, true),
  ('AT-6', 'Awareness and Training', 'Training Feedback', 'Provide feedback on organizational training results to the following personnel [Assignment: organization-defined frequency]: [Assignment: organization-defined personnel].', 'Protect', 'PR.AT', 'No baseline assignment', 5, true),
  ('AU-1', 'Audit and Accountability', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] audit and accountability policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the audit and accountability policy and the associated audit and accountability controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the audit and accountability policy and procedures; and c. Review and update the current audit and accountability: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AU-2', 'Audit and Accountability', 'Event Logging', 'a. Identify the types of events that the system is capable of logging in support of the audit function: [Assignment: organization-defined event types that the system is capable of logging]; b. Coordinate the event logging function with other organizational entities requiring audit-related information to guide and inform the selection criteria for events to be logged; c. Specify the following event types for logging within the system: [Assignment: organization-defined event types (subset of the event types defined in AU-2a.) along with the frequency of (or situation requiring) logging for each identified event type]; d. Provide a rationale for why the event types selected for logging are deemed to be adequate to support after-the-fact investigations of incidents; and e. Review and update the event types selected for logging [Assignment: organization-defined frequency].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AU-3', 'Audit and Accountability', 'Content of Audit Records', 'Ensure that audit records contain information that establishes the following: a. What type of event occurred; b. When the event occurred; c. Where the event occurred; d. Source of the event; e. Outcome of the event; and f. Identity of any individuals, subjects, or objects/entities associated with the event.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-4', 'Audit and Accountability', 'Audit Log Storage Capacity', 'Allocate audit log storage capacity to accommodate [Assignment: organization-defined audit log retention requirements].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-5', 'Audit and Accountability', 'Response to Audit Logging Process Failures', 'a. Alert [Assignment: organization-defined personnel or roles] within [Assignment: organization-defined time period] in the event of an audit logging process failure; and b. Take the following additional actions: [Assignment: organization-defined additional actions].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-6', 'Audit and Accountability', 'Audit Record Review, Analysis, and Reporting', 'a. Review and analyze system audit records [Assignment: organization-defined frequency] for indications of [Assignment: organization-defined inappropriate or unusual activity] and the potential impact of the inappropriate or unusual activity; b. Report findings to [Assignment: organization-defined personnel or roles]; and c. Adjust the level of audit record review, analysis, and reporting within the system when there is a change in risk based on law enforcement information, intelligence information, or other credible sources of information.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-7', 'Audit and Accountability', 'Audit Record Reduction and Report Generation', 'Provide and implement an audit record reduction and report generation capability that: a. Supports on-demand audit record review, analysis, and reporting requirements and after-the-fact investigations of incidents; and b. Does not alter the original content or time ordering of audit records.', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('AU-8', 'Audit and Accountability', 'Time Stamps', 'a. Use internal system clocks to generate time stamps for audit records; and b. Record time stamps for audit records that meet [Assignment: organization-defined granularity of time measurement] and that use Coordinated Universal Time, have a fixed local time offset from Coordinated Universal Time, or that include the local time offset as part of the time stamp.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-9', 'Audit and Accountability', 'Protection of Audit Information', 'a. Protect audit information and audit logging tools from unauthorized access, modification, and deletion; and b. Alert [Assignment: organization-defined personnel or roles] upon detection of unauthorized access, modification, or deletion of audit information.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-10', 'Audit and Accountability', 'Non-repudiation', 'Provide irrefutable evidence that an individual (or process acting on behalf of an individual) has performed [Assignment: organization-defined actions to be covered by non-repudiation].', 'Detect', 'DE.CM', 'Required for High baseline', 3, true),
  ('AU-11', 'Audit and Accountability', 'Audit Record Retention', 'Retain audit records for [Assignment: organization-defined time period consistent with records retention policy] to provide support for after-the-fact investigations of incidents and to meet regulatory and organizational information retention requirements.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('AU-12', 'Audit and Accountability', 'Audit Record Generation', 'a. Provide audit record generation capability for the event types the system is capable of auditing as defined in AU-2a on [Assignment: organization-defined system components]; b. Allow [Assignment: organization-defined personnel or roles] to select the event types that are to be logged by specific components of the system; and c. Generate audit records for the event types defined in AU-2c that include the audit record content defined in AU-3.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('AU-13', 'Audit and Accountability', 'Monitoring for Information Disclosure', 'a. Monitor [Assignment: organization-defined open-source information and/or information sites] [Assignment: organization-defined frequency] for evidence of unauthorized disclosure of organizational information; and b. If an information disclosure is discovered: 1. Notify [Assignment: organization-defined personnel or roles]; and 2. Take the following additional actions: [Assignment: organization-defined additional actions].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('AU-14', 'Audit and Accountability', 'Session Audit', 'a. Provide and implement the capability for [Assignment: organization-defined users or roles] to [Selection (one or more): record; view; hear; log] the content of a user session under [Assignment: organization-defined circumstances]; and b. Develop, integrate, and use session auditing activities in consultation with legal counsel and in accordance with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines.', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('AU-15', 'Audit and Accountability', 'Alternate Audit Logging Capability', 'Withdrawn', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('AU-16', 'Audit and Accountability', 'Cross-organizational Audit Logging', 'Employ [Assignment: organization-defined methods] for coordinating [Assignment: organization-defined audit information] among external organizations when audit information is transmitted across organizational boundaries.', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('CA-1', 'Assessment, Authorization, and Monitoring', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] assessment, authorization, and monitoring policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the assessment, authorization, and monitoring policy and the associated assessment, authorization, and monitoring controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the assessment, authorization, and monitoring policy and procedures; and c. Review and update the current assessment, authorization, and monitoring: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Identify', 'ID.IM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CA-2', 'Assessment, Authorization, and Monitoring', 'Control Assessments', 'a. Select the appropriate assessor or assessment team for the type of assessment to be conducted; b. Develop a control assessment plan that describes the scope of the assessment including: 1. Controls and control enhancements under assessment; 2. Assessment procedures to be used to determine control effectiveness; and 3. Assessment environment, assessment team, and assessment roles and responsibilities; c. Ensure the control assessment plan is reviewed and approved by the authorizing official or designated representative prior to conducting the assessment; d. Assess the controls in the system and its environment of operation [Assignment: organization-defined frequency] to determine the extent to which the controls are implemented correctly, operating as intended, and producing the desired outcome with respect to meeting established security and privacy requirements; e. Produce a control assessment report that document the results of the assessment; and f. Provide the results of the control assessment to [Assignment: organization-defined individuals or roles].', 'Identify', 'ID.IM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CA-3', 'Assessment, Authorization, and Monitoring', 'Information Exchange', 'a. Approve and manage the exchange of information between the system and other systems using [Selection (one or more): interconnection security agreements; information exchange security agreements; memoranda of understanding or agreement; service level agreements; user agreements; nondisclosure agreements; [Assignment: organization-defined type of agreement] ]; b. Document, as part of each exchange agreement, the interface characteristics, security and privacy requirements, controls, and responsibilities for each system, and the impact level of the information communicated; and c. Review and update the agreements [Assignment: organization-defined frequency].', 'Identify', 'ID.IM', 'Required for Low, Moderate, High baselines', 1, true),
  ('CA-4', 'Assessment, Authorization, and Monitoring', 'Security Certification', 'Withdrawn', 'Identify', 'ID.IM', 'No baseline assignment', 5, true),
  ('CA-5', 'Assessment, Authorization, and Monitoring', 'Plan of Action and Milestones', 'a. Develop a plan of action and milestones for the system to document the planned remediation actions of the organization to correct weaknesses or deficiencies noted during the assessment of the controls and to reduce or eliminate known vulnerabilities in the system; and b. Update existing plan of action and milestones [Assignment: organization-defined frequency] based on the findings from control assessments, independent audits or reviews, and continuous monitoring activities.', 'Identify', 'ID.IM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CA-6', 'Assessment, Authorization, and Monitoring', 'Authorization', 'a. Assign a senior official as the authorizing official for the system; b. Assign a senior official as the authorizing official for common controls available for inheritance by organizational systems; c. Ensure that the authorizing official for the system, before commencing operations: 1. Accepts the use of common controls inherited by the system; and 2. Authorizes the system to operate; d. Ensure that the authorizing official for common controls authorizes the use of those controls for inheritance by organizational systems; e. Update the authorizations [Assignment: organization-defined frequency].', 'Identify', 'ID.IM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CA-7', 'Assessment, Authorization, and Monitoring', 'Continuous Monitoring', 'Develop a system-level continuous monitoring strategy and implement continuous monitoring in accordance with the organization-level continuous monitoring strategy that includes: a. Establishing the following system-level metrics to be monitored: [Assignment: organization-defined system-level metrics]; b. Establishing [Assignment: organization-defined frequencies] for monitoring and [Assignment: organization-defined frequencies] for assessment of control effectiveness; c. Ongoing control assessments in accordance with the continuous monitoring strategy; d. Ongoing monitoring of system and organization-defined metrics in accordance with the continuous monitoring strategy; e. Correlation and analysis of information generated by control assessments and monitoring; f. Response actions to address results of the analysis of control assessment and monitoring information; and g. Reporting the security and privacy status of the system to [Assignment: organization-defined personnel or roles] [Assignment: organization-defined frequency].', 'Identify', 'ID.IM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CA-8', 'Assessment, Authorization, and Monitoring', 'Penetration Testing', 'Conduct penetration testing [Assignment: organization-defined frequency] on [Assignment: organization-defined systems or system components].', 'Identify', 'ID.IM', 'Required for High baseline', 3, true),
  ('CA-9', 'Assessment, Authorization, and Monitoring', 'Internal System Connections', 'a. Authorize internal connections of [Assignment: organization-defined system components or classes of components] to the system; b. Document, for each internal connection, the interface characteristics, security and privacy requirements, and the nature of the information communicated; c. Terminate internal system connections after [Assignment: organization-defined conditions]; and d. Review [Assignment: organization-defined frequency] the continued need for each internal connection.', 'Identify', 'ID.IM', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-1', 'Configuration Management', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] configuration management policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the configuration management policy and the associated configuration management controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the configuration management policy and procedures; and c. Review and update the current configuration management: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CM-2', 'Configuration Management', 'Baseline Configuration', 'a. Develop, document, and maintain under configuration control, a current baseline configuration of the system; and b. Review and update the baseline configuration of the system: 1. [Assignment: organization-defined frequency]; 2. When required due to [Assignment: Assignment organization-defined circumstances]; and 3. When system components are installed or upgraded.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-3', 'Configuration Management', 'Configuration Change Control', 'a. Determine and document the types of changes to the system that are configuration-controlled; b. Review proposed configuration-controlled changes to the system and approve or disapprove such changes with explicit consideration for security and privacy impact analyses; c. Document configuration change decisions associated with the system; d. Implement approved configuration-controlled changes to the system; e. Retain records of configuration-controlled changes to the system for [Assignment: organization-defined time period]; f. Monitor and review activities associated with configuration-controlled changes to the system; and g. Coordinate and provide oversight for configuration change control activities through [Assignment: organization-defined configuration change control element] that convenes [Selection (one or more): [Assignment: organization-defined frequency] ; when [Assignment: organization-defined configuration change conditions] ].', 'Protect', 'PR.PS', 'Required for Moderate, High baselines', 2, true),
  ('CM-4', 'Configuration Management', 'Impact Analyses', 'Analyze changes to the system to determine potential security and privacy impacts prior to change implementation.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('CM-5', 'Configuration Management', 'Access Restrictions for Change', 'Define, document, approve, and enforce physical and logical access restrictions associated with changes to the system.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-6', 'Configuration Management', 'Configuration Settings', 'a. Establish and document configuration settings for components employed within the system that reflect the most restrictive mode consistent with operational requirements using [Assignment: organization-defined common secure configurations]; b. Implement the configuration settings; c. Identify, document, and approve any deviations from established configuration settings for [Assignment: organization-defined system components] based on [Assignment: organization-defined operational requirements]; and d. Monitor and control changes to the configuration settings in accordance with organizational policies and procedures.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-7', 'Configuration Management', 'Least Functionality', 'a. Configure the system to provide only [Assignment: organization-defined mission essential capabilities]; and b. Prohibit or restrict the use of the following functions, ports, protocols, software, and/or services: [Assignment: organization-defined prohibited or restricted functions, system ports, protocols, software, and/or services].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-8', 'Configuration Management', 'System Component Inventory', 'a. Develop and document an inventory of system components that: 1. Accurately reflects the system; 2. Includes all components within the system; 3. Does not include duplicate accounting of components or components assigned to any other system; 4. Is at the level of granularity deemed necessary for tracking and reporting; and 5. Includes the following information to achieve system component accountability: [Assignment: organization-defined information deemed necessary to achieve effective system component accountability]; and b. Review and update the system component inventory [Assignment: organization-defined frequency].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-9', 'Configuration Management', 'Configuration Management Plan', 'Develop, document, and implement a configuration management plan for the system that: a. Addresses roles, responsibilities, and configuration management processes and procedures; b. Establishes a process for identifying configuration items throughout the system development life cycle and for managing the configuration of the configuration items; c. Defines the configuration items for the system and places the configuration items under configuration management; d. Is reviewed and approved by [Assignment: organization-defined personnel or roles]; and e. Protects the configuration management plan from unauthorized disclosure and modification.', 'Protect', 'PR.PS', 'Required for Moderate, High baselines', 2, true),
  ('CM-10', 'Configuration Management', 'Software Usage Restrictions', 'a. Use software and associated documentation in accordance with contract agreements and copyright laws; b. Track the use of software and associated documentation protected by quantity licenses to control copying and distribution; and c. Control and document the use of peer-to-peer file sharing technology to ensure that this capability is not used for the unauthorized distribution, display, performance, or reproduction of copyrighted work.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-11', 'Configuration Management', 'User-installed Software', 'a. Establish [Assignment: organization-defined policies] governing the installation of software by users; b. Enforce software installation policies through the following methods: [Assignment: organization-defined methods]; and c. Monitor policy compliance [Assignment: organization-defined frequency].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('CM-12', 'Configuration Management', 'Information Location', 'a. Identify and document the location of [Assignment: organization-defined information] and the specific system components on which the information is processed and stored; b. Identify and document the users who have access to the system and system components where the information is processed and stored; and c. Document changes to the location (i.e., system or system components) where the information is processed and stored.', 'Protect', 'PR.PS', 'Required for Moderate, High baselines', 2, true),
  ('CM-13', 'Configuration Management', 'Data Action Mapping', 'Develop and document a map of system data actions.', 'Protect', 'PR.PS', 'No baseline assignment', 5, true),
  ('CM-14', 'Configuration Management', 'Signed Components', 'Prevent the installation of [Assignment: organization-defined software and firmware components] without verification that the component has been digitally signed using a certificate that is recognized and approved by the organization.', 'Protect', 'PR.PS', 'No baseline assignment', 5, true),
  ('CP-1', 'Contingency Planning', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] contingency planning policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the contingency planning policy and the associated contingency planning controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the contingency planning policy and procedures; and c. Review and update the current contingency planning: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-2', 'Contingency Planning', 'Contingency Plan', 'a. Develop a contingency plan for the system that: 1. Identifies essential mission and business functions and associated contingency requirements; 2. Provides recovery objectives, restoration priorities, and metrics; 3. Addresses contingency roles, responsibilities, assigned individuals with contact information; 4. Addresses maintaining essential mission and business functions despite a system disruption, compromise, or failure; 5. Addresses eventual, full system restoration without deterioration of the controls originally planned and implemented; 6. Addresses the sharing of contingency information; and 7. Is reviewed and approved by [Assignment: organization-defined personnel or roles]; b. Distribute copies of the contingency plan to [Assignment: organization-defined key contingency personnel (identified by name and/or by role) and organizational elements]; c. Coordinate contingency planning activities with incident handling activities; d. Review the contingency plan for the system [Assignment: organization-defined frequency]; e. Update the contingency plan to address changes to the organization, system, or environment of operation and problems encountered during contingency plan implementation, execution, or testing; f. Communicate contingency plan changes to [Assignment: organization-defined key contingency personnel (identified by name and/or by role) and organizational elements]; g. Incorporate lessons learned from contingency plan testing, training, or actual contingency activities into contingency testing and training; and h. Protect the contingency plan from unauthorized disclosure and modification.', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-3', 'Contingency Planning', 'Contingency Training', 'a. Provide contingency training to system users consistent with assigned roles and responsibilities: 1. Within [Assignment: organization-defined time period] of assuming a contingency role or responsibility; 2. When required by system changes; and 3. [Assignment: organization-defined frequency] thereafter; and b. Review and update contingency training content [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-4', 'Contingency Planning', 'Contingency Plan Testing', 'a. Test the contingency plan for the system [Assignment: organization-defined frequency] using the following tests to determine the effectiveness of the plan and the readiness to execute the plan: [Assignment: organization-defined tests]. b. Review the contingency plan test results; and c. Initiate corrective actions, if needed.', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-5', 'Contingency Planning', 'Contingency Plan Update', 'Withdrawn', 'Recover', 'RC.RP', 'No baseline assignment', 5, true),
  ('CP-6', 'Contingency Planning', 'Alternate Storage Site', 'a. Establish an alternate storage site, including necessary agreements to permit the storage and retrieval of system backup information; and b. Ensure that the alternate storage site provides controls equivalent to that of the primary site.', 'Recover', 'RC.RP', 'Required for Moderate, High baselines', 2, true),
  ('CP-7', 'Contingency Planning', 'Alternate Processing Site', 'a. Establish an alternate processing site, including necessary agreements to permit the transfer and resumption of [Assignment: organization-defined system operations] for essential mission and business functions within [Assignment: organization-defined time period consistent with recovery time and recovery point objectives] when the primary processing capabilities are unavailable; b. Make available at the alternate processing site, the equipment and supplies required to transfer and resume operations or put contracts in place to support delivery to the site within the organization-defined time period for transfer and resumption; and c. Provide controls at the alternate processing site that are equivalent to those at the primary site.', 'Recover', 'RC.RP', 'Required for Moderate, High baselines', 2, true),
  ('CP-8', 'Contingency Planning', 'Telecommunications Services', 'Establish alternate telecommunications services, including necessary agreements to permit the resumption of [Assignment: organization-defined system operations] for essential mission and business functions within [Assignment: organization-defined time period] when the primary telecommunications capabilities are unavailable at either the primary or alternate processing or storage sites.', 'Recover', 'RC.RP', 'Required for Moderate, High baselines', 2, true),
  ('CP-9', 'Contingency Planning', 'System Backup', 'a. Conduct backups of user-level information contained in [Assignment: organization-defined system components] [Assignment: organization-defined frequency consistent with recovery time and recovery point objectives]; b. Conduct backups of system-level information contained in the system [Assignment: organization-defined frequency consistent with recovery time and recovery point objectives]; c. Conduct backups of system documentation, including security- and privacy-related documentation [Assignment: organization-defined frequency consistent with recovery time and recovery point objectives]; and d. Protect the confidentiality, integrity, and availability of backup information.', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-10', 'Contingency Planning', 'System Recovery and Reconstitution', 'Provide for the recovery and reconstitution of the system to a known state within [Assignment: organization-defined time period consistent with recovery time and recovery point objectives] after a disruption, compromise, or failure.', 'Recover', 'RC.RP', 'Required for Low, Moderate, High baselines', 1, true),
  ('CP-11', 'Contingency Planning', 'Alternate Communications Protocols', 'Provide the capability to employ [Assignment: organization-defined alternative communications protocols] in support of maintaining continuity of operations.', 'Recover', 'RC.RP', 'No baseline assignment', 5, true),
  ('CP-12', 'Contingency Planning', 'Safe Mode', 'When [Assignment: organization-defined conditions] are detected, enter a safe mode of operation with [Assignment: organization-defined restrictions of safe mode of operation].', 'Recover', 'RC.RP', 'No baseline assignment', 5, true),
  ('CP-13', 'Contingency Planning', 'Alternative Security Mechanisms', 'Employ [Assignment: organization-defined alternative or supplemental security mechanisms] for satisfying [Assignment: organization-defined security functions] when the primary means of implementing the security function is unavailable or compromised.', 'Recover', 'RC.RP', 'No baseline assignment', 5, true),
  ('IA-1', 'Identification and Authentication', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] identification and authentication policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the identification and authentication policy and the associated identification and authentication controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the identification and authentication policy and procedures; and c. Review and update the current identification and authentication: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-2', 'Identification and Authentication', 'Identification and Authentication (organizational Users)', 'Uniquely identify and authenticate organizational users and associate that unique identification with processes acting on behalf of those users.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-3', 'Identification and Authentication', 'Device Identification and Authentication', 'Uniquely identify and authenticate [Assignment: organization-defined devices and/or types of devices] before establishing a [Selection (one or more): local; remote; network] connection.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('IA-4', 'Identification and Authentication', 'Identifier Management', 'Manage system identifiers by: a. Receiving authorization from [Assignment: organization-defined personnel or roles] to assign an individual, group, role, service, or device identifier; b. Selecting an identifier that identifies an individual, group, role, service, or device; c. Assigning the identifier to the intended individual, group, role, service, or device; and d. Preventing reuse of identifiers for [Assignment: organization-defined time period].', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-5', 'Identification and Authentication', 'Authenticator Management', 'Manage system authenticators by: a. Verifying, as part of the initial authenticator distribution, the identity of the individual, group, role, service, or device receiving the authenticator; b. Establishing initial authenticator content for any authenticators issued by the organization; c. Ensuring that authenticators have sufficient strength of mechanism for their intended use; d. Establishing and implementing administrative procedures for initial authenticator distribution, for lost or compromised or damaged authenticators, and for revoking authenticators; e. Changing default authenticators prior to first use; f. Changing or refreshing authenticators [Assignment: organization-defined time period by authenticator type] or when [Assignment: organization-defined events] occur; g. Protecting authenticator content from unauthorized disclosure and modification; h. Requiring individuals to take, and having devices implement, specific controls to protect authenticators; and i. Changing authenticators for group or role accounts when membership to those accounts changes.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-6', 'Identification and Authentication', 'Authentication Feedback', 'Obscure feedback of authentication information during the authentication process to protect the information from possible exploitation and use by unauthorized individuals.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-7', 'Identification and Authentication', 'Cryptographic Module Authentication', 'Implement mechanisms for authentication to a cryptographic module that meet the requirements of applicable laws, executive orders, directives, policies, regulations, standards, and guidelines for such authentication.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-8', 'Identification and Authentication', 'Identification and Authentication (non-organizational Users)', 'Uniquely identify and authenticate non-organizational users or processes acting on behalf of non-organizational users.', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-9', 'Identification and Authentication', 'Service Identification and Authentication', 'Uniquely identify and authenticate [Assignment: organization-defined system services and applications] before establishing communications with devices, users, or other services or applications.', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('IA-10', 'Identification and Authentication', 'Adaptive Authentication', 'Require individuals accessing the system to employ [Assignment: organization-defined supplemental authentication techniques or mechanisms] under specific [Assignment: organization-defined circumstances or situations].', 'Protect', 'PR.AA', 'No baseline assignment', 5, true),
  ('IA-11', 'Identification and Authentication', 'Re-authentication', 'Require users to re-authenticate when [Assignment: organization-defined circumstances or situations requiring re-authentication].', 'Protect', 'PR.AA', 'Required for Low, Moderate, High baselines', 1, true),
  ('IA-12', 'Identification and Authentication', 'Identity Proofing', 'a. Identity proof users that require accounts for logical access to systems based on appropriate identity assurance level requirements as specified in applicable standards and guidelines; b. Resolve user identities to a unique individual; and c. Collect, validate, and verify identity evidence.', 'Protect', 'PR.AA', 'Required for Moderate, High baselines', 2, true),
  ('IR-1', 'Incident Response', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] incident response policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the incident response policy and the associated incident response controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the incident response policy and procedures; and c. Review and update the current incident response: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-2', 'Incident Response', 'Incident Response Training', 'a. Provide incident response training to system users consistent with assigned roles and responsibilities: 1. Within [Assignment: organization-defined time period] of assuming an incident response role or responsibility or acquiring system access; 2. When required by system changes; and 3. [Assignment: organization-defined frequency] thereafter; and b. Review and update incident response training content [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-3', 'Incident Response', 'Incident Response Testing', 'Test the effectiveness of the incident response capability for the system [Assignment: organization-defined frequency] using the following tests: [Assignment: organization-defined tests].', 'Respond', 'RS.MA', 'Required for Moderate, High, Privacy baselines', 2, true),
  ('IR-4', 'Incident Response', 'Incident Handling', 'a. Implement an incident handling capability for incidents that is consistent with the incident response plan and includes preparation, detection and analysis, containment, eradication, and recovery; b. Coordinate incident handling activities with contingency planning activities; c. Incorporate lessons learned from ongoing incident handling activities into incident response procedures, training, and testing, and implement the resulting changes accordingly; and d. Ensure the rigor, intensity, scope, and results of incident handling activities are comparable and predictable across the organization.', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-5', 'Incident Response', 'Incident Monitoring', 'Track and document incidents.', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-6', 'Incident Response', 'Incident Reporting', 'a. Require personnel to report suspected incidents to the organizational incident response capability within [Assignment: organization-defined time period]; and b. Report incident information to [Assignment: organization-defined authorities].', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-7', 'Incident Response', 'Incident Response Assistance', 'Provide an incident response support resource, integral to the organizational incident response capability, that offers advice and assistance to users of the system for the handling and reporting of incidents.', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-8', 'Incident Response', 'Incident Response Plan', 'a. Develop an incident response plan that: 1. Provides the organization with a roadmap for implementing its incident response capability; 2. Describes the structure and organization of the incident response capability; 3. Provides a high-level approach for how the incident response capability fits into the overall organization; 4. Meets the unique requirements of the organization, which relate to mission, size, structure, and functions; 5. Defines reportable incidents; 6. Provides metrics for measuring the incident response capability within the organization; 7. Defines the resources and management support needed to effectively maintain and mature an incident response capability; 8. Addresses the sharing of incident information; 9. Is reviewed and approved by [Assignment: organization-defined personnel or roles] [Assignment: organization-defined frequency]; and 10. Explicitly designates responsibility for incident response to [Assignment: organization-defined entities, personnel, or roles]. b. Distribute copies of the incident response plan to [Assignment: organization-defined incident response personnel (identified by name and/or by role) and organizational elements]; c. Update the incident response plan to address system and organizational changes or problems encountered during plan implementation, execution, or testing; d. Communicate incident response plan changes to [Assignment: organization-defined incident response personnel (identified by name and/or by role) and organizational elements]; and e. Protect the incident response plan from unauthorized disclosure and modification.', 'Respond', 'RS.MA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('IR-9', 'Incident Response', 'Information Spillage Response', 'Respond to information spills by: a. Assigning [Assignment: organization-defined personnel or roles] with responsibility for responding to information spills; b. Identifying the specific information involved in the system contamination; c. Alerting [Assignment: organization-defined personnel or roles] of the information spill using a method of communication not associated with the spill; d. Isolating the contaminated system or system component; e. Eradicating the information from the contaminated system or component; f. Identifying other systems or system components that may have been subsequently contaminated; and g. Performing the following additional actions: [Assignment: organization-defined actions].', 'Respond', 'RS.MA', 'No baseline assignment', 5, true),
  ('IR-10', 'Incident Response', 'Incident Analysis', 'Withdrawn', 'Respond', 'RS.MA', 'No baseline assignment', 5, true),
  ('MA-1', 'Maintenance', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] maintenance policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the maintenance policy and the associated maintenance controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the maintenance policy and procedures; and c. Review and update the current maintenance: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MA-2', 'Maintenance', 'Controlled Maintenance', 'a. Schedule, document, and review records of maintenance, repair, and replacement on system components in accordance with manufacturer or vendor specifications and/or organizational requirements; b. Approve and monitor all maintenance activities, whether performed on site or remotely and whether the system or system components are serviced on site or removed to another location; c. Require that [Assignment: organization-defined personnel or roles] explicitly approve the removal of the system or system components from organizational facilities for off-site maintenance, repair, or replacement; d. Sanitize equipment to remove the following information from associated media prior to removal from organizational facilities for off-site maintenance, repair, or replacement: [Assignment: organization-defined information]; e. Check all potentially impacted controls to verify that the controls are still functioning properly following maintenance, repair, or replacement actions; and f. Include the following information in organizational maintenance records: [Assignment: organization-defined information].', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MA-3', 'Maintenance', 'Maintenance Tools', 'a. Approve, control, and monitor the use of system maintenance tools; and b. Review previously approved system maintenance tools [Assignment: organization-defined frequency].', 'Protect', 'PR.PS', 'Required for Moderate, High baselines', 2, true),
  ('MA-4', 'Maintenance', 'Nonlocal Maintenance', 'a. Approve and monitor nonlocal maintenance and diagnostic activities; b. Allow the use of nonlocal maintenance and diagnostic tools only as consistent with organizational policy and documented in the security plan for the system; c. Employ strong authentication in the establishment of nonlocal maintenance and diagnostic sessions; d. Maintain records for nonlocal maintenance and diagnostic activities; and e. Terminate session and network connections when nonlocal maintenance is completed.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MA-5', 'Maintenance', 'Maintenance Personnel', 'a. Establish a process for maintenance personnel authorization and maintain a list of authorized maintenance organizations or personnel; b. Verify that non-escorted personnel performing maintenance on the system possess the required access authorizations; and c. Designate organizational personnel with required access authorizations and technical competence to supervise the maintenance activities of personnel who do not possess the required access authorizations.', 'Protect', 'PR.PS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MA-6', 'Maintenance', 'Timely Maintenance', 'Obtain maintenance support and/or spare parts for [Assignment: organization-defined system components] within [Assignment: organization-defined time period] of failure.', 'Protect', 'PR.PS', 'Required for Moderate, High baselines', 2, true),
  ('MA-7', 'Maintenance', 'Field Maintenance', 'Restrict or prohibit field maintenance on [Assignment: organization-defined systems or system components] to [Assignment: organization-defined trusted maintenance facilities].', 'Protect', 'PR.PS', 'No baseline assignment', 5, true),
  ('MP-1', 'Media Protection', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] media protection policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the media protection policy and the associated media protection controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the media protection policy and procedures; and c. Review and update the current media protection: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('MP-2', 'Media Protection', 'Media Access', 'Restrict access to [Assignment: organization-defined types of digital and/or non-digital media] to [Assignment: organization-defined personnel or roles].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MP-3', 'Media Protection', 'Media Marking', 'a. Mark system media indicating the distribution limitations, handling caveats, and applicable security markings (if any) of the information; and b. Exempt [Assignment: organization-defined types of system media] from marking if the media remain within [Assignment: organization-defined controlled areas].', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('MP-4', 'Media Protection', 'Media Storage', 'a. Physically control and securely store [Assignment: organization-defined types of digital and/or non-digital media] within [Assignment: organization-defined controlled areas]; and b. Protect system media types defined in MP-4a until the media are destroyed or sanitized using approved equipment, techniques, and procedures.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('MP-5', 'Media Protection', 'Media Transport', 'a. Protect and control [Assignment: organization-defined types of system media] during transport outside of controlled areas using [Assignment: organization-defined controls]; b. Maintain accountability for system media during transport outside of controlled areas; c. Document activities associated with the transport of system media; and d. Restrict the activities associated with the transport of system media to authorized personnel.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('MP-6', 'Media Protection', 'Media Sanitization', 'a. Sanitize [Assignment: organization-defined system media] prior to disposal, release out of organizational control, or release for reuse using [Assignment: organization-defined sanitization techniques and procedures]; and b. Employ sanitization mechanisms with the strength and integrity commensurate with the security category or classification of the information.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('MP-7', 'Media Protection', 'Media Use', 'a. [Selection: Restrict; Prohibit] the use of [Assignment: organization-defined types of system media] on [Assignment: organization-defined systems or system components] using [Assignment: organization-defined controls]; and b. Prohibit the use of portable storage devices in organizational systems when such devices have no identifiable owner.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('MP-8', 'Media Protection', 'Media Downgrading', 'a. Establish [Assignment: organization-defined system media downgrading process] that includes employing downgrading mechanisms with strength and integrity commensurate with the security category or classification of the information; b. Verify that the system media downgrading process is commensurate with the security category and/or classification level of the information to be removed and the access authorizations of the potential recipients of the downgraded information; c. Identify [Assignment: organization-defined system media requiring downgrading]; and d. Downgrade the identified system media using the established process.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('PE-1', 'Physical and Environmental Protection', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] physical and environmental protection policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the physical and environmental protection policy and the associated physical and environmental protection controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the physical and environmental protection policy and procedures; and c. Review and update the current physical and environmental protection: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-2', 'Physical and Environmental Protection', 'Physical Access Authorizations', 'a. Develop, approve, and maintain a list of individuals with authorized access to the facility where the system resides; b. Issue authorization credentials for facility access; c. Review the access list detailing authorized facility access by individuals [Assignment: organization-defined frequency]; and d. Remove individuals from the facility access list when access is no longer required.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-3', 'Physical and Environmental Protection', 'Physical Access Control', 'a. Enforce physical access authorizations at [Assignment: organization-defined entry and exit points to the facility where the system resides] by: 1. Verifying individual access authorizations before granting access to the facility; and 2. Controlling ingress and egress to the facility using [Selection (one or more): [Assignment: organization-defined physical access control systems or devices] ; guards]; b. Maintain physical access audit logs for [Assignment: organization-defined entry or exit points]; c. Control access to areas within the facility designated as publicly accessible by implementing the following controls: [Assignment: organization-defined physical access controls]; d. Escort visitors and control visitor activity [Assignment: organization-defined circumstances requiring visitor escorts and control of visitor activity]; e. Secure keys, combinations, and other physical access devices; f. Inventory [Assignment: organization-defined physical access devices] every [Assignment: organization-defined frequency]; and g. Change combinations and keys [Assignment: organization-defined frequency] and/or when keys are lost, combinations are compromised, or when individuals possessing the keys or combinations are transferred or terminated.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-4', 'Physical and Environmental Protection', 'Access Control for Transmission', 'Control physical access to [Assignment: organization-defined system distribution and transmission lines] within organizational facilities using [Assignment: organization-defined security controls].', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-5', 'Physical and Environmental Protection', 'Access Control for Output Devices', 'Control physical access to output from [Assignment: organization-defined output devices] to prevent unauthorized individuals from obtaining the output.', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-6', 'Physical and Environmental Protection', 'Monitoring Physical Access', 'a. Monitor physical access to the facility where the system resides to detect and respond to physical security incidents; b. Review physical access logs [Assignment: organization-defined frequency] and upon occurrence of [Assignment: organization-defined events or potential indications of events]; and c. Coordinate results of reviews and investigations with the organizational incident response capability.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-7', 'Physical and Environmental Protection', 'Visitor Control', 'Withdrawn', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PE-8', 'Physical and Environmental Protection', 'Visitor Access Records', 'a. Maintain visitor access records to the facility where the system resides for [Assignment: organization-defined time period]; b. Review visitor access records [Assignment: organization-defined frequency]; and c. Report anomalies in visitor access records to [Assignment: organization-defined personnel].', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-9', 'Physical and Environmental Protection', 'Power Equipment and Cabling', 'Protect power equipment and power cabling for the system from damage and destruction.', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-10', 'Physical and Environmental Protection', 'Emergency Shutoff', 'a. Provide the capability of shutting off power to [Assignment: organization-defined system or individual system components] in emergency situations; b. Place emergency shutoff switches or devices in [Assignment: organization-defined location by system or system component] to facilitate access for authorized personnel; and c. Protect emergency power shutoff capability from unauthorized activation.', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-11', 'Physical and Environmental Protection', 'Emergency Power', 'Provide an uninterruptible power supply to facilitate [Selection (one or more): an orderly shutdown of the system; transition of the system to long-term alternate power] in the event of a primary power source loss.', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-12', 'Physical and Environmental Protection', 'Emergency Lighting', 'Employ and maintain automatic emergency lighting for the system that activates in the event of a power outage or disruption and that covers emergency exits and evacuation routes within the facility.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-13', 'Physical and Environmental Protection', 'Fire Protection', 'Employ and maintain fire detection and suppression systems that are supported by an independent energy source.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-14', 'Physical and Environmental Protection', 'Environmental Controls', 'a. Maintain [Selection (one or more): temperature; humidity; pressure; radiation; [Assignment: organization-defined environmental control] ] levels within the facility where the system resides at [Assignment: organization-defined acceptable levels]; and b. Monitor environmental control levels [Assignment: organization-defined frequency].', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-15', 'Physical and Environmental Protection', 'Water Damage Protection', 'Protect the system from damage resulting from water leakage by providing master shutoff or isolation valves that are accessible, working properly, and known to key personnel.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-16', 'Physical and Environmental Protection', 'Delivery and Removal', 'a. Authorize and control [Assignment: organization-defined types of system components] entering and exiting the facility; and b. Maintain records of the system components.', 'Protect', 'PR.IR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PE-17', 'Physical and Environmental Protection', 'Alternate Work Site', 'a. Determine and document the [Assignment: organization-defined alternate work sites] allowed for use by employees; b. Employ the following controls at alternate work sites: [Assignment: organization-defined controls]; c. Assess the effectiveness of controls at alternate work sites; and d. Provide a means for employees to communicate with information security and privacy personnel in case of incidents.', 'Protect', 'PR.IR', 'Required for Moderate, High baselines', 2, true),
  ('PE-18', 'Physical and Environmental Protection', 'Location of System Components', 'Position system components within the facility to minimize potential damage from [Assignment: organization-defined physical and environmental hazards] and to minimize the opportunity for unauthorized access.', 'Protect', 'PR.IR', 'Required for High baseline', 3, true),
  ('PE-19', 'Physical and Environmental Protection', 'Information Leakage', 'Protect the system from information leakage due to electromagnetic signals emanations.', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PE-20', 'Physical and Environmental Protection', 'Asset Monitoring and Tracking', 'Employ [Assignment: organization-defined asset location technologies] to track and monitor the location and movement of [Assignment: organization-defined assets] within [Assignment: organization-defined controlled areas].', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PE-21', 'Physical and Environmental Protection', 'Electromagnetic Pulse Protection', 'Employ [Assignment: organization-defined protective measures] against electromagnetic pulse damage for [Assignment: organization-defined systems and system components].', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PE-22', 'Physical and Environmental Protection', 'Component Marking', 'Mark [Assignment: organization-defined system hardware components] indicating the impact level or classification level of the information permitted to be processed, stored, or transmitted by the hardware component.', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PE-23', 'Physical and Environmental Protection', 'Facility Location', 'a. Plan the location or site of the facility where the system resides considering physical and environmental hazards; and b. For existing facilities, consider the physical and environmental hazards in the organizational risk management strategy.', 'Protect', 'PR.IR', 'No baseline assignment', 5, true),
  ('PL-1', 'Planning', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] planning policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the planning policy and the associated planning controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the planning policy and procedures; and c. Review and update the current planning: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Govern', 'GV.RM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('PL-2', 'Planning', 'System Security and Privacy Plans', 'a. Develop security and privacy plans for the system that: 1. Are consistent with the organization’s enterprise architecture; 2. Explicitly define the constituent system components; 3. Describe the operational context of the system in terms of mission and business processes; 4. Identify the individuals that fulfill system roles and responsibilities; 5. Identify the information types processed, stored, and transmitted by the system; 6. Provide the security categorization of the system, including supporting rationale; 7. Describe any specific threats to the system that are of concern to the organization; 8. Provide the results of a privacy risk assessment for systems processing personally identifiable information; 9. Describe the operational environment for the system and any dependencies on or connections to other systems or system components; 10. Provide an overview of the security and privacy requirements for the system; 11. Identify any relevant control baselines or overlays, if applicable; 12. Describe the controls in place or planned for meeting the security and privacy requirements, including a rationale for any tailoring decisions; 13. Include risk determinations for security and privacy architecture and design decisions; 14. Include security- and privacy-related activities affecting the system that require planning and coordination with [Assignment: organization-defined individuals or groups]; and 15. Are reviewed and approved by the authorizing official or designated representative prior to plan implementation. b. Distribute copies of the plans and communicate subsequent changes to the plans to [Assignment: organization-defined personnel or roles]; c. Review the plans [Assignment: organization-defined frequency]; d. Update the plans to address changes to the system and environment of operation or problems identified during plan implementation or control assessments; and e. Protect the plans from unauthorized disclosure and modification.', 'Govern', 'GV.RM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('PL-3', 'Planning', 'System Security Plan Update', 'Withdrawn', 'Govern', 'GV.RM', 'No baseline assignment', 5, true),
  ('PL-4', 'Planning', 'Rules of Behavior', 'a. Establish and provide to individuals requiring access to the system, the rules that describe their responsibilities and expected behavior for information and system usage, security, and privacy; b. Receive a documented acknowledgment from such individuals, indicating that they have read, understand, and agree to abide by the rules of behavior, before authorizing access to information and the system; c. Review and update the rules of behavior [Assignment: organization-defined frequency]; and d. Require individuals who have acknowledged a previous version of the rules of behavior to read and re-acknowledge [Selection (one or more): [Assignment: organization-defined frequency] ; when the rules are revised or updated].', 'Govern', 'GV.RM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('PL-5', 'Planning', 'Privacy Impact Assessment', 'Withdrawn', 'Govern', 'GV.RM', 'No baseline assignment', 5, true),
  ('PL-6', 'Planning', 'Security-related Activity Planning', 'Withdrawn', 'Govern', 'GV.RM', 'No baseline assignment', 5, true),
  ('PL-7', 'Planning', 'Concept of Operations', 'a. Develop a Concept of Operations (CONOPS) for the system describing how the organization intends to operate the system from the perspective of information security and privacy; and b. Review and update the CONOPS [Assignment: organization-defined frequency].', 'Govern', 'GV.RM', 'No baseline assignment', 5, true),
  ('PL-8', 'Planning', 'Security and Privacy Architectures', 'a. Develop security and privacy architectures for the system that: 1. Describe the requirements and approach to be taken for protecting the confidentiality, integrity, and availability of organizational information; 2. Describe the requirements and approach to be taken for processing personally identifiable information to minimize privacy risk to individuals; 3. Describe how the architectures are integrated into and support the enterprise architecture; and 4. Describe any assumptions about, and dependencies on, external systems and services; b. Review and update the architectures [Assignment: organization-defined frequency] to reflect changes in the enterprise architecture; and c. Reflect planned architecture changes in security and privacy plans, Concept of Operations (CONOPS), criticality analysis, organizational procedures, and procurements and acquisitions.', 'Govern', 'GV.RM', 'Required for Moderate, High, Privacy baselines', 2, true),
  ('PL-9', 'Planning', 'Central Management', 'Centrally manage [Assignment: organization-defined controls and related processes].', 'Govern', 'GV.RM', 'Required for Privacy baseline', 4, true),
  ('PL-10', 'Planning', 'Baseline Selection', 'Select a control baseline for the system.', 'Govern', 'GV.RM', 'Required for Low, Moderate, High baselines', 1, true),
  ('PL-11', 'Planning', 'Baseline Tailoring', 'Tailor the selected control baseline by applying specified tailoring actions.', 'Govern', 'GV.RM', 'Required for Low, Moderate, High baselines', 1, true),
  ('PM-1', 'Program Management', 'Information Security Program Plan', 'a. Develop and disseminate an organization-wide information security program plan that: 1. Provides an overview of the requirements for the security program and a description of the security program management controls and common controls in place or planned for meeting those requirements; 2. Includes the identification and assignment of roles, responsibilities, management commitment, coordination among organizational entities, and compliance; 3. Reflects the coordination among organizational entities responsible for information security; and 4. Is approved by a senior official with responsibility and accountability for the risk being incurred to organizational operations (including mission, functions, image, and reputation), organizational assets, individuals, other organizations, and the Nation; b. Review and update the organization-wide information security program plan [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and c. Protect the information security program plan from unauthorized disclosure and modification.', 'Govern', 'GV.OC', 'Required for Low baseline', 1, true),
  ('PM-2', 'Program Management', 'Information Security Program Leadership Role', 'Appoint a senior agency information security officer with the mission and resources to coordinate, develop, implement, and maintain an organization-wide information security program.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-3', 'Program Management', 'Information Security and Privacy Resources', 'a. Include the resources needed to implement the information security and privacy programs in capital planning and investment requests and document all exceptions to this requirement; b. Prepare documentation required for addressing information security and privacy programs in capital planning and investment requests in accordance with applicable laws, executive orders, directives, policies, regulations, standards; and c. Make available for expenditure, the planned information security and privacy resources.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-4', 'Program Management', 'Plan of Action and Milestones Process', 'a. Implement a process to ensure that plans of action and milestones for the information security, privacy, and supply chain risk management programs and associated organizational systems: 1. Are developed and maintained; 2. Document the remedial information security, privacy, and supply chain risk management actions to adequately respond to risk to organizational operations and assets, individuals, other organizations, and the Nation; and 3. Are reported in accordance with established reporting requirements. b. Review plans of action and milestones for consistency with the organizational risk management strategy and organization-wide priorities for risk response actions.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-5', 'Program Management', 'System Inventory', 'Develop and update [Assignment: organization-defined frequency] an inventory of organizational systems.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-6', 'Program Management', 'Measures of Performance', 'Develop, monitor, and report on the results of information security and privacy measures of performance.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-7', 'Program Management', 'Enterprise Architecture', 'Develop and maintain an enterprise architecture with consideration for information security, privacy, and the resulting risk to organizational operations and assets, individuals, other organizations, and the Nation.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-8', 'Program Management', 'Critical Infrastructure Plan', 'Address information security and privacy issues in the development, documentation, and updating of a critical infrastructure and key resources protection plan.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-9', 'Program Management', 'Risk Management Strategy', 'a. Develops a comprehensive strategy to manage: 1. Security risk to organizational operations and assets, individuals, other organizations, and the Nation associated with the operation and use of organizational systems; and 2. Privacy risk to individuals resulting from the authorized processing of personally identifiable information; b. Implement the risk management strategy consistently across the organization; and c. Review and update the risk management strategy [Assignment: organization-defined frequency] or as required, to address organizational changes.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-10', 'Program Management', 'Authorization Process', 'a. Manage the security and privacy state of organizational systems and the environments in which those systems operate through authorization processes; b. Designate individuals to fulfill specific roles and responsibilities within the organizational risk management process; and c. Integrate the authorization processes into an organization-wide risk management program.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-11', 'Program Management', 'Mission and Business Process Definition', 'a. Define organizational mission and business processes with consideration for information security and privacy and the resulting risk to organizational operations, organizational assets, individuals, other organizations, and the Nation; and b. Determine information protection and personally identifiable information processing needs arising from the defined mission and business processes; and c. Review and revise the mission and business processes [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-12', 'Program Management', 'Insider Threat Program', 'Implement an insider threat program that includes a cross-discipline insider threat incident handling team.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-13', 'Program Management', 'Security and Privacy Workforce', 'Establish a security and privacy workforce development and improvement program.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-14', 'Program Management', 'Testing, Training, and Monitoring', 'a. Implement a process for ensuring that organizational plans for conducting security and privacy testing, training, and monitoring activities associated with organizational systems: 1. Are developed and maintained; and 2. Continue to be executed; and b. Review testing, training, and monitoring plans for consistency with the organizational risk management strategy and organization-wide priorities for risk response actions.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-15', 'Program Management', 'Security and Privacy Groups and Associations', 'Establish and institutionalize contact with selected groups and associations within the security and privacy communities: a. To facilitate ongoing security and privacy education and training for organizational personnel; b. To maintain currency with recommended security and privacy practices, techniques, and technologies; and c. To share current security and privacy information, including threats, vulnerabilities, and incidents.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-16', 'Program Management', 'Threat Awareness Program', 'Implement a threat awareness program that includes a cross-organization information-sharing capability for threat intelligence.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-17', 'Program Management', 'Protecting Controlled Unclassified Information on External Systems', 'a. Establish policy and procedures to ensure that requirements for the protection of controlled unclassified information that is processed, stored or transmitted on external systems, are implemented in accordance with applicable laws, executive orders, directives, policies, regulations, and standards; and b. Review and update the policy and procedures [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-18', 'Program Management', 'Privacy Program Plan', 'a. Develop and disseminate an organization-wide privacy program plan that provides an overview of the agency’s privacy program, and: 1. Includes a description of the structure of the privacy program and the resources dedicated to the privacy program; 2. Provides an overview of the requirements for the privacy program and a description of the privacy program management controls and common controls in place or planned for meeting those requirements; 3. Includes the role of the senior agency official for privacy and the identification and assignment of roles of other privacy officials and staff and their responsibilities; 4. Describes management commitment, compliance, and the strategic goals and objectives of the privacy program; 5. Reflects coordination among organizational entities responsible for the different aspects of privacy; and 6. Is approved by a senior official with responsibility and accountability for the privacy risk being incurred to organizational operations (including mission, functions, image, and reputation), organizational assets, individuals, other organizations, and the Nation; and b. Update the plan [Assignment: organization-defined frequency] and to address changes in federal privacy laws and policy and organizational changes and problems identified during plan implementation or privacy control assessments.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-19', 'Program Management', 'Privacy Program Leadership Role', 'Appoint a senior agency official for privacy with the authority, mission, accountability, and resources to coordinate, develop, and implement, applicable privacy requirements and manage privacy risks through the organization-wide privacy program.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-20', 'Program Management', 'Dissemination of Privacy Program Information', 'Maintain a central resource webpage on the organization’s principal public website that serves as a central source of information about the organization’s privacy program and that: a. Ensures that the public has access to information about organizational privacy activities and can communicate with its senior agency official for privacy; b. Ensures that organizational privacy practices and reports are publicly available; and c. Employs publicly facing email addresses and/or phone lines to enable the public to provide feedback and/or direct questions to privacy offices regarding privacy practices.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-21', 'Program Management', 'Accounting of Disclosures', 'a. Develop and maintain an accurate accounting of disclosures of personally identifiable information, including: 1. Date, nature, and purpose of each disclosure; and 2. Name and address, or other contact information of the individual or organization to which the disclosure was made; b. Retain the accounting of disclosures for the length of the time the personally identifiable information is maintained or five years after the disclosure is made, whichever is longer; and c. Make the accounting of disclosures available to the individual to whom the personally identifiable information relates upon request.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-22', 'Program Management', 'Personally Identifiable Information Quality Management', 'Develop and document organization-wide policies and procedures for: a. Reviewing for the accuracy, relevance, timeliness, and completeness of personally identifiable information across the information life cycle; b. Correcting or deleting inaccurate or outdated personally identifiable information; c. Disseminating notice of corrected or deleted personally identifiable information to individuals or other appropriate entities; and d. Appeals of adverse decisions on correction or deletion requests.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-23', 'Program Management', 'Data Governance Body', 'Establish a Data Governance Body consisting of [Assignment: organization-defined roles] with [Assignment: organization-defined responsibilities].', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-24', 'Program Management', 'Data Integrity Board', 'Establish a Data Integrity Board to: a. Review proposals to conduct or participate in a matching program; and b. Conduct an annual review of all matching programs in which the agency has participated.', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-25', 'Program Management', 'Minimization of Personally Identifiable Information Used in Testing, Training, and Research', 'a. Develop, document, and implement policies and procedures that address the use of personally identifiable information for internal testing, training, and research; b. Limit or minimize the amount of personally identifiable information used for internal testing, training, and research purposes; c. Authorize the use of personally identifiable information when such information is required for internal testing, training, and research; and d. Review and update policies and procedures [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-26', 'Program Management', 'Complaint Management', 'Implement a process for receiving and responding to complaints, concerns, or questions from individuals about the organizational security and privacy practices that includes: a. Mechanisms that are easy to use and readily accessible by the public; b. All information necessary for successfully filing complaints; c. Tracking mechanisms to ensure all complaints received are reviewed and addressed within [Assignment: organization-defined time period]; d. Acknowledgement of receipt of complaints, concerns, or questions from individuals within [Assignment: organization-defined time period]; and e. Response to complaints, concerns, or questions from individuals within [Assignment: organization-defined time period].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-27', 'Program Management', 'Privacy Reporting', 'a. Develop [Assignment: organization-defined privacy reports] and disseminate to: 1. [Assignment: organization-defined oversight bodies] to demonstrate accountability with statutory, regulatory, and policy privacy mandates; and 2. [Assignment: organization-defined officials] and other personnel with responsibility for monitoring privacy program compliance; and b. Review and update privacy reports [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-28', 'Program Management', 'Risk Framing', 'a. Identify and document: 1. Assumptions affecting risk assessments, risk responses, and risk monitoring; 2. Constraints affecting risk assessments, risk responses, and risk monitoring; 3. Priorities and trade-offs considered by the organization for managing risk; and 4. Organizational risk tolerance; b. Distribute the results of risk framing activities to [Assignment: organization-defined personnel]; and c. Review and update risk framing considerations [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-29', 'Program Management', 'Risk Management Program Leadership Roles', 'a. Appoint a Senior Accountable Official for Risk Management to align organizational information security and privacy management processes with strategic, operational, and budgetary planning processes; and b. Establish a Risk Executive (function) to view and analyze risk from an organization-wide perspective and ensure management of risk is consistent across the organization.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-30', 'Program Management', 'Supply Chain Risk Management Strategy', 'a. Develop an organization-wide strategy for managing supply chain risks associated with the development, acquisition, maintenance, and disposal of systems, system components, and system services; b. Implement the supply chain risk management strategy consistently across the organization; and c. Review and update the supply chain risk management strategy on [Assignment: organization-defined frequency] or as required, to address organizational changes.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PM-31', 'Program Management', 'Continuous Monitoring Strategy', 'Develop an organization-wide continuous monitoring strategy and implement continuous monitoring programs that include: a. Establishing the following organization-wide metrics to be monitored: [Assignment: organization-defined metrics]; b. Establishing [Assignment: organization-defined frequencies] for monitoring and [Assignment: organization-defined frequencies] for assessment of control effectiveness; c. Ongoing monitoring of organizationally-defined metrics in accordance with the continuous monitoring strategy; d. Correlation and analysis of information generated by control assessments and monitoring; e. Response actions to address results of the analysis of control assessment and monitoring information; and f. Reporting the security and privacy status of organizational systems to [Assignment: organization-defined personnel or roles] [Assignment: organization-defined frequency].', 'Govern', 'GV.OC', 'Required for Privacy baseline', 4, true),
  ('PM-32', 'Program Management', 'Purposing', 'Analyze [Assignment: organization-defined systems or systems components] supporting mission essential services or functions to ensure that the information resources are being used consistent with their intended purpose.', 'Govern', 'GV.OC', 'No baseline assignment', 5, true),
  ('PS-1', 'Personnel Security', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] personnel security policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the personnel security policy and the associated personnel security controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the personnel security policy and procedures; and c. Review and update the current personnel security: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-2', 'Personnel Security', 'Position Risk Designation', 'a. Assign a risk designation to all organizational positions; b. Establish screening criteria for individuals filling those positions; and c. Review and update position risk designations [Assignment: organization-defined frequency].', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-3', 'Personnel Security', 'Personnel Screening', 'a. Screen individuals prior to authorizing access to the system; and b. Rescreen individuals in accordance with [Assignment: organization-defined conditions requiring rescreening and, where rescreening is so indicated, the frequency of rescreening].', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-4', 'Personnel Security', 'Personnel Termination', 'Upon termination of individual employment: a. Disable system access within [Assignment: organization-defined time period]; b. Terminate or revoke any authenticators and credentials associated with the individual; c. Conduct exit interviews that include a discussion of [Assignment: organization-defined information security topics]; d. Retrieve all security-related organizational system-related property; and e. Retain access to organizational information and systems formerly controlled by terminated individual.', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-5', 'Personnel Security', 'Personnel Transfer', 'a. Review and confirm ongoing operational need for current logical and physical access authorizations to systems and facilities when individuals are reassigned or transferred to other positions within the organization; b. Initiate [Assignment: organization-defined transfer or reassignment actions] within [Assignment: organization-defined time period following the formal transfer action]; c. Modify access authorization as needed to correspond with any changes in operational need due to reassignment or transfer; and d. Notify [Assignment: organization-defined personnel or roles] within [Assignment: organization-defined time period].', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-6', 'Personnel Security', 'Access Agreements', 'a. Develop and document access agreements for organizational systems; b. Review and update the access agreements [Assignment: organization-defined frequency]; and c. Verify that individuals requiring access to organizational information and systems: 1. Sign appropriate access agreements prior to being granted access; and 2. Re-sign access agreements to maintain access to organizational systems when access agreements have been updated or [Assignment: organization-defined frequency].', 'Govern', 'GV.RR', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('PS-7', 'Personnel Security', 'External Personnel Security', 'a. Establish personnel security requirements, including security roles and responsibilities for external providers; b. Require external providers to comply with personnel security policies and procedures established by the organization; c. Document personnel security requirements; d. Require external providers to notify [Assignment: organization-defined personnel or roles] of any personnel transfers or terminations of external personnel who possess organizational credentials and/or badges, or who have system privileges within [Assignment: organization-defined time period]; and e. Monitor provider compliance with personnel security requirements.', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-8', 'Personnel Security', 'Personnel Sanctions', 'a. Employ a formal sanctions process for individuals failing to comply with established information security and privacy policies and procedures; and b. Notify [Assignment: organization-defined personnel or roles] within [Assignment: organization-defined time period] when a formal employee sanctions process is initiated, identifying the individual sanctioned and the reason for the sanction.', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PS-9', 'Personnel Security', 'Position Descriptions', 'Incorporate security and privacy roles and responsibilities into organizational position descriptions.', 'Govern', 'GV.RR', 'Required for Low, Moderate, High baselines', 1, true),
  ('PT-1', 'PII Processing and Transparency', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] personally identifiable information processing and transparency policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the personally identifiable information processing and transparency policy and the associated personally identifiable information processing and transparency controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the personally identifiable information processing and transparency policy and procedures; and c. Review and update the current personally identifiable information processing and transparency: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.DS', 'Required for Low, Privacy baselines', 1, true),
  ('PT-2', 'PII Processing and Transparency', 'Authority to Process Personally Identifiable Information', 'a. Determine and document the [Assignment: organization-defined authority] that permits the [Assignment: organization-defined processing] of personally identifiable information; and b. Restrict the [Assignment: organization-defined processing] of personally identifiable information to only that which is authorized.', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-3', 'PII Processing and Transparency', 'Personally Identifiable Information Processing Purposes', 'a. Identify and document the [Assignment: Assignment organization-defined purpose(s)] for processing personally identifiable information; b. Describe the purpose(s) in the public privacy notices and policies of the organization; c. Restrict the [Assignment: organization-defined processing] of personally identifiable information to only that which is compatible with the identified purpose(s); and d. Monitor changes in processing personally identifiable information and implement [Assignment: organization-defined mechanisms] to ensure that any changes are made in accordance with [Assignment: organization-defined requirements].', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-4', 'PII Processing and Transparency', 'Consent', 'Implement [Assignment: organization-defined tools or mechanisms] for individuals to consent to the processing of their personally identifiable information prior to its collection that facilitate individuals’ informed decision-making.', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-5', 'PII Processing and Transparency', 'Privacy Notice', 'Provide notice to individuals about the processing of personally identifiable information that: a. Is available to individuals upon first interacting with an organization, and subsequently at [Assignment: organization-defined frequency]; b. Is clear and easy-to-understand, expressing information about personally identifiable information processing in plain language; c. Identifies the authority that authorizes the processing of personally identifiable information; d. Identifies the purposes for which personally identifiable information is to be processed; and e. Includes [Assignment: organization-defined information].', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-6', 'PII Processing and Transparency', 'System of Records Notice', 'For systems that process information that will be maintained in a Privacy Act system of records: a. Draft system of records notices in accordance with OMB guidance and submit new and significantly modified system of records notices to the OMB and appropriate congressional committees for advance review; b. Publish system of records notices in the Federal Register; and c. Keep system of records notices accurate, up-to-date, and scoped in accordance with policy.', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-7', 'PII Processing and Transparency', 'Specific Categories of Personally Identifiable Information', 'Apply [Assignment: organization-defined processing conditions] for specific categories of personally identifiable information.', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('PT-8', 'PII Processing and Transparency', 'Computer Matching Requirements', 'When a system or organization processes information for the purpose of conducting a matching program: a. Obtain approval from the Data Integrity Board to conduct the matching program; b. Develop and enter into a computer matching agreement; c. Publish a matching notice in the Federal Register; d. Independently verify the information produced by the matching program before taking adverse action against an individual, if required; and e. Provide individuals with notice and an opportunity to contest the findings before taking adverse action against an individual.', 'Protect', 'PR.DS', 'Required for Privacy baseline', 4, true),
  ('RA-1', 'Risk Assessment', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] risk assessment policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the risk assessment policy and the associated risk assessment controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the risk assessment policy and procedures; and c. Review and update the current risk assessment: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Identify', 'ID.RA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('RA-2', 'Risk Assessment', 'Security Categorization', 'a. Categorize the system and information it processes, stores, and transmits; b. Document the security categorization results, including supporting rationale, in the security plan for the system; and c. Verify that the authorizing official or authorizing official designated representative reviews and approves the security categorization decision.', 'Identify', 'ID.RA', 'Required for Low, Moderate, High baselines', 1, true),
  ('RA-3', 'Risk Assessment', 'Risk Assessment', 'a. Conduct a risk assessment, including: 1. Identifying threats to and vulnerabilities in the system; 2. Determining the likelihood and magnitude of harm from unauthorized access, use, disclosure, disruption, modification, or destruction of the system, the information it processes, stores, or transmits, and any related information; and 3. Determining the likelihood and impact of adverse effects on individuals arising from the processing of personally identifiable information; b. Integrate risk assessment results and risk management decisions from the organization and mission or business process perspectives with system-level risk assessments; c. Document risk assessment results in [Selection: security and privacy plans; risk assessment report; [Assignment: organization-defined document] ]; d. Review risk assessment results [Assignment: organization-defined frequency]; e. Disseminate risk assessment results to [Assignment: organization-defined personnel or roles]; and f. Update the risk assessment [Assignment: organization-defined frequency] or when there are significant changes to the system, its environment of operation, or other conditions that may impact the security or privacy state of the system.', 'Identify', 'ID.RA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('RA-4', 'Risk Assessment', 'Risk Assessment Update', 'Withdrawn', 'Identify', 'ID.RA', 'No baseline assignment', 5, true),
  ('RA-5', 'Risk Assessment', 'Vulnerability Monitoring and Scanning', 'a. Monitor and scan for vulnerabilities in the system and hosted applications [Assignment: organization-defined frequency and/or randomly in accordance with organization-defined process] and when new vulnerabilities potentially affecting the system are identified and reported; b. Employ vulnerability monitoring tools and techniques that facilitate interoperability among tools and automate parts of the vulnerability management process by using standards for: 1. Enumerating platforms, software flaws, and improper configurations; 2. Formatting checklists and test procedures; and 3. Measuring vulnerability impact; c. Analyze vulnerability scan reports and results from vulnerability monitoring; d. Remediate legitimate vulnerabilities [Assignment: organization-defined response times] in accordance with an organizational assessment of risk; e. Share information obtained from the vulnerability monitoring process and control assessments with [Assignment: organization-defined personnel or roles] to help eliminate similar vulnerabilities in other systems; and f. Employ vulnerability monitoring tools that include the capability to readily update the vulnerabilities to be scanned.', 'Identify', 'ID.RA', 'Required for Low, Moderate, High baselines', 1, true),
  ('RA-6', 'Risk Assessment', 'Technical Surveillance Countermeasures Survey', 'Employ a technical surveillance countermeasures survey at [Assignment: organization-defined locations] [Selection (one or more): [Assignment: organization-defined frequency] ; when the following events or indicators occur; [Assignment: organization-defined events or indicators] ].', 'Identify', 'ID.RA', 'No baseline assignment', 5, true),
  ('RA-7', 'Risk Assessment', 'Risk Response', 'Respond to findings from security and privacy assessments, monitoring, and audits in accordance with organizational risk tolerance.', 'Identify', 'ID.RA', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('RA-8', 'Risk Assessment', 'Privacy Impact Assessments', 'Conduct privacy impact assessments for systems, programs, or other activities before: a. Developing or procuring information technology that processes personally identifiable information; and b. Initiating a new collection of personally identifiable information that: 1. Will be processed using information technology; and 2. Includes personally identifiable information permitting the physical or virtual (online) contacting of a specific individual, if identical questions have been posed to, or identical reporting requirements imposed on, ten or more individuals, other than agencies, instrumentalities, or employees of the federal government.', 'Identify', 'ID.RA', 'Required for Privacy baseline', 4, true),
  ('RA-9', 'Risk Assessment', 'Criticality Analysis', 'Identify critical system components and functions by performing a criticality analysis for [Assignment: organization-defined systems, system components, or system services] at [Assignment: organization-defined decision points in the system development life cycle].', 'Identify', 'ID.RA', 'Required for Moderate, High baselines', 2, true),
  ('RA-10', 'Risk Assessment', 'Threat Hunting', 'a. Establish and maintain a cyber threat hunting capability to: 1. Search for indicators of compromise in organizational systems; and 2. Detect, track, and disrupt threats that evade existing controls; and b. Employ the threat hunting capability [Assignment: organization-defined frequency].', 'Identify', 'ID.RA', 'No baseline assignment', 5, true),
  ('SA-1', 'System and Services Acquisition', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] system and services acquisition policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the system and services acquisition policy and the associated system and services acquisition controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the system and services acquisition policy and procedures; and c. Review and update the current system and services acquisition: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SA-2', 'System and Services Acquisition', 'Allocation of Resources', 'a. Determine the high-level information security and privacy requirements for the system or system service in mission and business process planning; b. Determine, document, and allocate the resources required to protect the system or system service as part of the organizational capital planning and investment control process; and c. Establish a discrete line item for information security and privacy in organizational programming and budgeting documentation.', 'Govern', 'GV.SC', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SA-3', 'System and Services Acquisition', 'System Development Life Cycle', 'a. Acquire, develop, and manage the system using [Assignment: organization-defined system development life cycle] that incorporates information security and privacy considerations; b. Define and document information security and privacy roles and responsibilities throughout the system development life cycle; c. Identify individuals having information security and privacy roles and responsibilities; and d. Integrate the organizational information security and privacy risk management process into system development life cycle activities.', 'Govern', 'GV.SC', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SA-4', 'System and Services Acquisition', 'Acquisition Process', 'Include the following requirements, descriptions, and criteria, explicitly or by reference, using [Selection (one or more): standardized contract language; [Assignment: organization-defined contract language] ] in the acquisition contract for the system, system component, or system service: a. Security and privacy functional requirements; b. Strength of mechanism requirements; c. Security and privacy assurance requirements; d. Controls needed to satisfy the security and privacy requirements. e. Security and privacy documentation requirements; f. Requirements for protecting security and privacy documentation; g. Description of the system development environment and environment in which the system is intended to operate; h. Allocation of responsibility or identification of parties responsible for information security, privacy, and supply chain risk management; and i. Acceptance criteria.', 'Govern', 'GV.SC', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SA-5', 'System and Services Acquisition', 'System Documentation', 'a. Obtain or develop administrator documentation for the system, system component, or system service that describes: 1. Secure configuration, installation, and operation of the system, component, or service; 2. Effective use and maintenance of security and privacy functions and mechanisms; and 3. Known vulnerabilities regarding configuration and use of administrative or privileged functions; b. Obtain or develop user documentation for the system, system component, or system service that describes: 1. User-accessible security and privacy functions and mechanisms and how to effectively use those functions and mechanisms; 2. Methods for user interaction, which enables individuals to use the system, component, or service in a more secure manner and protect individual privacy; and 3. User responsibilities in maintaining the security of the system, component, or service and privacy of individuals; c. Document attempts to obtain system, system component, or system service documentation when such documentation is either unavailable or nonexistent and take [Assignment: organization-defined actions] in response; and d. Distribute documentation to [Assignment: organization-defined personnel or roles].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SA-6', 'System and Services Acquisition', 'Software Usage Restrictions', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-7', 'System and Services Acquisition', 'User-installed Software', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-8', 'System and Services Acquisition', 'Security and Privacy Engineering Principles', 'Apply the following systems security and privacy engineering principles in the specification, design, development, implementation, and modification of the system and system components: [Assignment: organization-defined systems security and privacy engineering principles].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SA-9', 'System and Services Acquisition', 'External System Services', 'a. Require that providers of external system services comply with organizational security and privacy requirements and employ the following controls: [Assignment: organization-defined controls]; b. Define and document organizational oversight and user roles and responsibilities with regard to external system services; and c. Employ the following processes, methods, and techniques to monitor control compliance by external service providers on an ongoing basis: [Assignment: organization-defined processes, methods, and techniques].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SA-10', 'System and Services Acquisition', 'Developer Configuration Management', 'Require the developer of the system, system component, or system service to: a. Perform configuration management during system, component, or service [Selection (one or more): design; development; implementation; operation; disposal]; b. Document, manage, and control the integrity of changes to [Assignment: organization-defined configuration items under configuration management]; c. Implement only organization-approved changes to the system, component, or service; d. Document approved changes to the system, component, or service and the potential security and privacy impacts of such changes; and e. Track security flaws and flaw resolution within the system, component, or service and report findings to [Assignment: organization-defined personnel].', 'Govern', 'GV.SC', 'Required for Moderate, High baselines', 2, true),
  ('SA-11', 'System and Services Acquisition', 'Developer Testing and Evaluation', 'Require the developer of the system, system component, or system service, at all post-design stages of the system development life cycle, to: a. Develop and implement a plan for ongoing security and privacy assessments; b. Perform [Selection (one or more): unit; integration; system; regression] testing/evaluation [Assignment: organization-defined frequency] at [Assignment: organization-defined depth and coverage]; c. Produce evidence of the execution of the assessment plan and the results of the testing and evaluation; d. Implement a verifiable flaw remediation process; and e. Correct flaws identified during testing and evaluation.', 'Govern', 'GV.SC', 'Required for Moderate, High, Privacy baselines', 2, true),
  ('SA-12', 'System and Services Acquisition', 'Supply Chain Protection', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-13', 'System and Services Acquisition', 'Trustworthiness', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-14', 'System and Services Acquisition', 'Criticality Analysis', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-15', 'System and Services Acquisition', 'Development Process, Standards, and Tools', 'a. Require the developer of the system, system component, or system service to follow a documented development process that: 1. Explicitly addresses security and privacy requirements; 2. Identifies the standards and tools used in the development process; 3. Documents the specific tool options and tool configurations used in the development process; and 4. Documents, manages, and ensures the integrity of changes to the process and/or tools used in development; and b. Review the development process, standards, tools, tool options, and tool configurations [Assignment: organization-defined frequency] to determine if the process, standards, tools, tool options and tool configurations selected and employed can satisfy the following security and privacy requirements: [Assignment: organization-defined security and privacy requirements].', 'Govern', 'GV.SC', 'Required for Moderate, High baselines', 2, true),
  ('SA-16', 'System and Services Acquisition', 'Developer-provided Training', 'Require the developer of the system, system component, or system service to provide the following training on the correct use and operation of the implemented security and privacy functions, controls, and/or mechanisms: [Assignment: organization-defined training].', 'Govern', 'GV.SC', 'Required for High baseline', 3, true),
  ('SA-17', 'System and Services Acquisition', 'Developer Security and Privacy Architecture and Design', 'Require the developer of the system, system component, or system service to produce a design specification and security and privacy architecture that: a. Is consistent with the organization’s security and privacy architecture that is an integral part the organization’s enterprise architecture; b. Accurately and completely describes the required security and privacy functionality, and the allocation of controls among physical and logical components; and c. Expresses how individual security and privacy functions, mechanisms, and services work together to provide required security and privacy capabilities and a unified approach to protection.', 'Govern', 'GV.SC', 'Required for High baseline', 3, true),
  ('SA-18', 'System and Services Acquisition', 'Tamper Resistance and Detection', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-19', 'System and Services Acquisition', 'Component Authenticity', 'Withdrawn', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-20', 'System and Services Acquisition', 'Customized Development of Critical Components', 'Reimplement or custom develop the following critical system components: [Assignment: organization-defined critical system components].', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SA-21', 'System and Services Acquisition', 'Developer Screening', 'Require that the developer of [Assignment: organization-defined system, system component, or system service]: a. Has appropriate access authorizations as determined by assigned [Assignment: organization-defined official government duties]; and b. Satisfies the following additional personnel screening criteria: [Assignment: organization-defined additional personnel screening criteria].', 'Govern', 'GV.SC', 'Required for High baseline', 3, true),
  ('SA-22', 'System and Services Acquisition', 'Unsupported System Components', 'a. Replace system components when support for the components is no longer available from the developer, vendor, or manufacturer; or b. Provide the following options for alternative sources for continued support for unsupported components [Selection (one or more): in-house support; [Assignment: organization-defined support from external providers] ].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SA-23', 'System and Services Acquisition', 'Specialization', 'Employ [Selection (one or more): design modification; augmentation; reconfiguration] on [Assignment: organization-defined systems or system components] supporting mission essential services or functions to increase the trustworthiness in those systems or components.', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SC-1', 'System and Communications Protection', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] system and communications protection policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the system and communications protection policy and the associated system and communications protection controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the system and communications protection policy and procedures; and c. Review and update the current system and communications protection: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-2', 'System and Communications Protection', 'Separation of System and User Functionality', 'Separate user functionality, including user interface services, from system management functionality.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-3', 'System and Communications Protection', 'Security Function Isolation', 'Isolate security functions from nonsecurity functions.', 'Protect', 'PR.DS', 'Required for High baseline', 3, true),
  ('SC-4', 'System and Communications Protection', 'Information in Shared System Resources', 'Prevent unauthorized and unintended information transfer via shared system resources.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-5', 'System and Communications Protection', 'Denial-of-service Protection', 'a. [Selection: Protect against; Limit] the effects of the following types of denial-of-service events: [Assignment: organization-defined types of denial-of-service events]; and b. Employ the following controls to achieve the denial-of-service objective: [Assignment: organization-defined controls by type of denial-of-service event].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-6', 'System and Communications Protection', 'Resource Availability', 'Protect the availability of resources by allocating [Assignment: organization-defined resources] by [Selection (one or more): priority; quota; [Assignment: organization-defined controls] ].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-7', 'System and Communications Protection', 'Boundary Protection', 'a. Monitor and control communications at the external managed interfaces to the system and at key internal managed interfaces within the system; b. Implement subnetworks for publicly accessible system components that are [Selection: physically; logically] separated from internal organizational networks; and c. Connect to external networks or systems only through managed interfaces consisting of boundary protection devices arranged in accordance with an organizational security and privacy architecture.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-8', 'System and Communications Protection', 'Transmission Confidentiality and Integrity', 'Protect the [Selection (one or more): confidentiality; integrity] of transmitted information.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-9', 'System and Communications Protection', 'Transmission Confidentiality', 'Withdrawn', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-10', 'System and Communications Protection', 'Network Disconnect', 'Terminate the network connection associated with a communications session at the end of the session or after [Assignment: organization-defined time period] of inactivity.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-11', 'System and Communications Protection', 'Trusted Path', 'a. Provide a [Selection: physically; logically] isolated trusted communications path for communications between the user and the trusted components of the system; and b. Permit users to invoke the trusted communications path for communications between the user and the following security functions of the system, including at a minimum, authentication and re-authentication: [Assignment: organization-defined security functions].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-12', 'System and Communications Protection', 'Cryptographic Key Establishment and Management', 'Establish and manage cryptographic keys when cryptography is employed within the system in accordance with the following key management requirements: [Assignment: organization-defined requirements for key generation, distribution, storage, access, and destruction].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-13', 'System and Communications Protection', 'Cryptographic Protection', 'a. Determine the [Assignment: organization-defined cryptographic uses]; and b. Implement the following types of cryptography required for each specified cryptographic use: [Assignment: organization-defined types of cryptography for each specified cryptographic use].', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-14', 'System and Communications Protection', 'Public Access Protections', 'Withdrawn', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-15', 'System and Communications Protection', 'Collaborative Computing Devices and Applications', 'a. Prohibit remote activation of collaborative computing devices and applications with the following exceptions: [Assignment: organization-defined exceptions where remote activation is to be allowed]; and b. Provide an explicit indication of use to users physically present at the devices.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-16', 'System and Communications Protection', 'Transmission of Security and Privacy Attributes', 'Associate [Assignment: organization-defined security and privacy attributes] with information exchanged between systems and between system components.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-17', 'System and Communications Protection', 'Public Key Infrastructure Certificates', 'a. Issue public key certificates under an [Assignment: organization-defined certificate policy] or obtain public key certificates from an approved service provider; and b. Include only approved trust anchors in trust stores or certificate stores managed by the organization.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-18', 'System and Communications Protection', 'Mobile Code', 'a. Define acceptable and unacceptable mobile code and mobile code technologies; and b. Authorize, monitor, and control the use of mobile code within the system.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-19', 'System and Communications Protection', 'Voice Over Internet Protocol', 'Withdrawn', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-20', 'System and Communications Protection', 'Secure Name/address Resolution Service (authoritative Source)', 'a. Provide additional data origin authentication and integrity verification artifacts along with the authoritative name resolution data the system returns in response to external name/address resolution queries; and b. Provide the means to indicate the security status of child zones and (if the child supports secure resolution services) to enable verification of a chain of trust among parent and child domains, when operating as part of a distributed, hierarchical namespace.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-21', 'System and Communications Protection', 'Secure Name/address Resolution Service (recursive or Caching Resolver)', 'Request and perform data origin authentication and data integrity verification on the name/address resolution responses the system receives from authoritative sources.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-22', 'System and Communications Protection', 'Architecture and Provisioning for Name/address Resolution Service', 'Ensure the systems that collectively provide name/address resolution service for an organization are fault-tolerant and implement internal and external role separation.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-23', 'System and Communications Protection', 'Session Authenticity', 'Protect the authenticity of communications sessions.', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-24', 'System and Communications Protection', 'Fail in Known State', 'Fail to a [Assignment: organization-defined known system state] for the following failures on the indicated components while preserving [Assignment: organization-defined system state information] in failure: [Assignment: list of organization-defined types of system failures on organization-defined system components].', 'Protect', 'PR.DS', 'Required for High baseline', 3, true),
  ('SC-25', 'System and Communications Protection', 'Thin Nodes', 'Employ minimal functionality and information storage on the following system components: [Assignment: organization-defined system components].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-26', 'System and Communications Protection', 'Decoys', 'Include components within organizational systems specifically designed to be the target of malicious attacks for detecting, deflecting, and analyzing such attacks.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-27', 'System and Communications Protection', 'Platform-independent Applications', 'Include within organizational systems the following platform independent applications: [Assignment: organization-defined platform-independent applications].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-28', 'System and Communications Protection', 'Protection of Information at Rest', 'Protect the [Selection (one or more): confidentiality; integrity] of the following information at rest: [Assignment: organization-defined information at rest].', 'Protect', 'PR.DS', 'Required for Moderate, High baselines', 2, true),
  ('SC-29', 'System and Communications Protection', 'Heterogeneity', 'Employ a diverse set of information technologies for the following system components in the implementation of the system: [Assignment: organization-defined system components].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-30', 'System and Communications Protection', 'Concealment and Misdirection', 'Employ the following concealment and misdirection techniques for [Assignment: organization-defined systems] at [Assignment: organization-defined time periods] to confuse and mislead adversaries: [Assignment: organization-defined concealment and misdirection techniques].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-31', 'System and Communications Protection', 'Covert Channel Analysis', 'a. Perform a covert channel analysis to identify those aspects of communications within the system that are potential avenues for covert [Selection (one or more): storage; timing] channels; and b. Estimate the maximum bandwidth of those channels.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-32', 'System and Communications Protection', 'System Partitioning', 'Partition the system into [Assignment: organization-defined system components] residing in separate [Selection: physical; logical] domains or environments based on [Assignment: organization-defined circumstances for physical or logical separation of components].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-33', 'System and Communications Protection', 'Transmission Preparation Integrity', 'Withdrawn', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-34', 'System and Communications Protection', 'Non-modifiable Executable Programs', 'For [Assignment: organization-defined system components], load and execute: a. The operating environment from hardware-enforced, read-only media; and b. The following applications from hardware-enforced, read-only media: [Assignment: organization-defined applications].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-35', 'System and Communications Protection', 'External Malicious Code Identification', 'Include system components that proactively seek to identify network-based malicious code or malicious websites.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-36', 'System and Communications Protection', 'Distributed Processing and Storage', 'Distribute the following processing and storage components across multiple [Selection: physical locations; logical domains]: [Assignment: organization-defined processing and storage components].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-37', 'System and Communications Protection', 'Out-of-band Channels', 'Employ the following out-of-band channels for the physical delivery or electronic transmission of [Assignment: organization-defined information, system components, or devices] to [Assignment: organization-defined individuals or systems]: [Assignment: organization-defined out-of-band channels].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-38', 'System and Communications Protection', 'Operations Security', 'Employ the following operations security controls to protect key organizational information throughout the system development life cycle: [Assignment: organization-defined operations security controls].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-39', 'System and Communications Protection', 'Process Isolation', 'Maintain a separate execution domain for each executing system process.', 'Protect', 'PR.DS', 'Required for Low, Moderate, High baselines', 1, true),
  ('SC-40', 'System and Communications Protection', 'Wireless Link Protection', 'Protect external and internal [Assignment: organization-defined wireless links] from the following signal parameter attacks: [Assignment: organization-defined types of signal parameter attacks or references to sources for such attacks].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-41', 'System and Communications Protection', 'Port and I/O Device Access', '[Selection: Physically; Logically] disable or remove [Assignment: organization-defined connection ports or input/output devices] on the following systems or system components: [Assignment: organization-defined systems or system components].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-42', 'System and Communications Protection', 'Sensor Capability and Data', 'a. Prohibit [Selection (one or more): the use of devices possessing [Assignment: organization-defined environmental sensing capabilities] in [Assignment: organization-defined facilities, areas, or systems] ; the remote activation of environmental sensing capabilities on organizational systems or system components with the following exceptions; [Assignment: organization-defined exceptions where remote activation of sensors is allowed] ]; and b. Provide an explicit indication of sensor use to [Assignment: organization-defined class of users].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-43', 'System and Communications Protection', 'Usage Restrictions', 'a. Establish usage restrictions and implementation guidelines for the following system components: [Assignment: organization-defined system components]; and b. Authorize, monitor, and control the use of such components within the system.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-44', 'System and Communications Protection', 'Detonation Chambers', 'Employ a detonation chamber capability within [Assignment: organization-defined system, system component, or location].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-45', 'System and Communications Protection', 'System Time Synchronization', 'Synchronize system clocks within and between systems and system components.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-46', 'System and Communications Protection', 'Cross Domain Policy Enforcement', 'Implement a policy enforcement mechanism [Selection: physically; logically] between the physical and/or network interfaces for the connecting security domains.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-47', 'System and Communications Protection', 'Alternate Communications Paths', 'Establish [Assignment: organization-defined alternate communications paths] for system operations organizational command and control.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-48', 'System and Communications Protection', 'Sensor Relocation', 'Relocate [Assignment: organization-defined sensors and monitoring capabilities] to [Assignment: organization-defined locations] under the following conditions or circumstances: [Assignment: organization-defined conditions or circumstances].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-49', 'System and Communications Protection', 'Hardware-enforced Separation and Policy Enforcement', 'Implement hardware-enforced separation and policy enforcement mechanisms between [Assignment: organization-defined security domains].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-50', 'System and Communications Protection', 'Software-enforced Separation and Policy Enforcement', 'Implement software-enforced separation and policy enforcement mechanisms between [Assignment: organization-defined security domains].', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SC-51', 'System and Communications Protection', 'Hardware-based Protection', 'a. Employ hardware-based, write-protect for [Assignment: organization-defined system firmware components]; and b. Implement specific procedures for [Assignment: organization-defined authorized individuals] to manually disable hardware write-protect for firmware modifications and re-enable the write-protect prior to returning to operational mode.', 'Protect', 'PR.DS', 'No baseline assignment', 5, true),
  ('SI-1', 'System and Information Integrity', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] system and information integrity policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the system and information integrity policy and the associated system and information integrity controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the system and information integrity policy and procedures; and c. Review and update the current system and information integrity: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SI-2', 'System and Information Integrity', 'Flaw Remediation', 'a. Identify, report, and correct system flaws; b. Test software and firmware updates related to flaw remediation for effectiveness and potential side effects before installation; c. Install security-relevant software and firmware updates within [Assignment: organization-defined time period] of the release of the updates; and d. Incorporate flaw remediation into the organizational configuration management process.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('SI-3', 'System and Information Integrity', 'Malicious Code Protection', 'a. Implement [Selection (one or more): signature based; non-signature based] malicious code protection mechanisms at system entry and exit points to detect and eradicate malicious code; b. Automatically update malicious code protection mechanisms as new releases are available in accordance with organizational configuration management policy and procedures; c. Configure malicious code protection mechanisms to: 1. Perform periodic scans of the system [Assignment: organization-defined frequency] and real-time scans of files from external sources at [Selection (one or more): endpoint; network entry and exit points] as the files are downloaded, opened, or executed in accordance with organizational policy; and 2. [Selection (one or more): block malicious code; quarantine malicious code; take [Assignment: organization-defined action] ]; and send alert to [Assignment: organization-defined personnel or roles] in response to malicious code detection; and d. Address the receipt of false positives during malicious code detection and eradication and the resulting potential impact on the availability of the system.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('SI-4', 'System and Information Integrity', 'System Monitoring', 'a. Monitor the system to detect: 1. Attacks and indicators of potential attacks in accordance with the following monitoring objectives: [Assignment: organization-defined monitoring objectives]; and 2. Unauthorized local, network, and remote connections; b. Identify unauthorized use of the system through the following techniques and methods: [Assignment: organization-defined techniques and methods]; c. Invoke internal monitoring capabilities or deploy monitoring devices: 1. Strategically within the system to collect organization-determined essential information; and 2. At ad hoc locations within the system to track specific types of transactions of interest to the organization; d. Analyze detected events and anomalies; e. Adjust the level of system monitoring activity when there is a change in risk to organizational operations and assets, individuals, other organizations, or the Nation; f. Obtain legal opinion regarding system monitoring activities; and g. Provide [Assignment: organization-defined system monitoring information] to [Assignment: organization-defined personnel or roles] [Selection (one or more): as needed; [Assignment: organization-defined frequency] ].', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('SI-5', 'System and Information Integrity', 'Security Alerts, Advisories, and Directives', 'a. Receive system security alerts, advisories, and directives from [Assignment: organization-defined external organizations] on an ongoing basis; b. Generate internal security alerts, advisories, and directives as deemed necessary; c. Disseminate security alerts, advisories, and directives to: [Selection (one or more): [Assignment: organization-defined personnel or roles] ; [Assignment: organization-defined elements within the organization] ; [Assignment: organization-defined external organizations] ]; and d. Implement security directives in accordance with established time frames, or notify the issuing organization of the degree of noncompliance.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High baselines', 1, true),
  ('SI-6', 'System and Information Integrity', 'Security and Privacy Function Verification', 'a. Verify the correct operation of [Assignment: organization-defined security and privacy functions]; b. Perform the verification of the functions specified in SI-6a [Selection (one or more): [Assignment: organization-defined system transitional states] ; upon command by user with appropriate privilege; [Assignment: organization-defined frequency] ]; c. Alert [Assignment: organization-defined personnel or roles] to failed security and privacy verification tests; and d. [Selection (one or more): Shut the system down; Restart the system; [Assignment: organization-defined alternative action(s)] ] when anomalies are discovered.', 'Detect', 'DE.CM', 'Required for High baseline', 3, true),
  ('SI-7', 'System and Information Integrity', 'Software, Firmware, and Information Integrity', 'a. Employ integrity verification tools to detect unauthorized changes to the following software, firmware, and information: [Assignment: organization-defined software, firmware, and information]; and b. Take the following actions when unauthorized changes to the software, firmware, and information are detected: [Assignment: organization-defined actions].', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('SI-8', 'System and Information Integrity', 'Spam Protection', 'a. Employ spam protection mechanisms at system entry and exit points to detect and act on unsolicited messages; and b. Update spam protection mechanisms when new releases are available in accordance with organizational configuration management policy and procedures.', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('SI-9', 'System and Information Integrity', 'Information Input Restrictions', 'Withdrawn', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-10', 'System and Information Integrity', 'Information Input Validation', 'Check the validity of the following information inputs: [Assignment: organization-defined information inputs to the system].', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('SI-11', 'System and Information Integrity', 'Error Handling', 'a. Generate error messages that provide information necessary for corrective actions without revealing information that could be exploited; and b. Reveal error messages only to [Assignment: organization-defined personnel or roles].', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('SI-12', 'System and Information Integrity', 'Information Management and Retention', 'Manage and retain information within the system and information output from the system in accordance with applicable laws, executive orders, directives, regulations, policies, standards, guidelines and operational requirements.', 'Detect', 'DE.CM', 'Required for Low, Moderate, High, Privacy baselines', 1, true),
  ('SI-13', 'System and Information Integrity', 'Predictable Failure Prevention', 'a. Determine mean time to failure (MTTF) for the following system components in specific environments of operation: [Assignment: organization-defined system components]; and b. Provide substitute system components and a means to exchange active and standby components in accordance with the following criteria: [Assignment: organization-defined MTTF substitution criteria].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-14', 'System and Information Integrity', 'Non-persistence', 'Implement non-persistent [Assignment: organization-defined system components and services] that are initiated in a known state and terminated [Selection (one or more): upon end of session of use; periodically at [Assignment: organization-defined frequency] ].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-15', 'System and Information Integrity', 'Information Output Filtering', 'Validate information output from the following software programs and/or applications to ensure that the information is consistent with the expected content: [Assignment: organization-defined software programs and/or applications].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-16', 'System and Information Integrity', 'Memory Protection', 'Implement the following controls to protect the system memory from unauthorized code execution: [Assignment: organization-defined controls].', 'Detect', 'DE.CM', 'Required for Moderate, High baselines', 2, true),
  ('SI-17', 'System and Information Integrity', 'Fail-safe Procedures', 'Implement the indicated fail-safe procedures when the indicated failures occur: [Assignment: organization-defined list of failure conditions and associated fail-safe procedures].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-18', 'System and Information Integrity', 'Personally Identifiable Information Quality Operations', 'a. Check the accuracy, relevance, timeliness, and completeness of personally identifiable information across the information life cycle [Assignment: organization-defined frequency]; and b. Correct or delete inaccurate or outdated personally identifiable information.', 'Detect', 'DE.CM', 'Required for Privacy baseline', 4, true),
  ('SI-19', 'System and Information Integrity', 'De-identification', 'a. Remove the following elements of personally identifiable information from datasets: [Assignment: organization-defined elements of personally identifiable information]; and b. Evaluate [Assignment: organization-defined frequency] for effectiveness of de-identification.', 'Detect', 'DE.CM', 'Required for Privacy baseline', 4, true),
  ('SI-20', 'System and Information Integrity', 'Tainting', 'Embed data or capabilities in the following systems or system components to determine if organizational data has been exfiltrated or improperly removed from the organization: [Assignment: organization-defined systems or system components].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-21', 'System and Information Integrity', 'Information Refresh', 'Refresh [Assignment: organization-defined information] at [Assignment: organization-defined frequencies] or generate the information on demand and delete the information when no longer needed.', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-22', 'System and Information Integrity', 'Information Diversity', 'a. Identify the following alternative sources of information for [Assignment: organization-defined essential functions and services]: [Assignment: organization-defined alternative information sources]; and b. Use an alternative information source for the execution of essential functions or services on [Assignment: organization-defined systems or system components] when the primary source of information is corrupted or unavailable.', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SI-23', 'System and Information Integrity', 'Information Fragmentation', 'Based on [Assignment: organization-defined circumstances]: a. Fragment the following information: [Assignment: organization-defined information]; and b. Distribute the fragmented information across the following systems or system components: [Assignment: Assignment organization-defined systems or system components].', 'Detect', 'DE.CM', 'No baseline assignment', 5, true),
  ('SR-1', 'Supply Chain Risk Management', 'Policy and Procedures', 'a. Develop, document, and disseminate to [Assignment: organization-defined personnel or roles]: 1. [Selection (one or more): organization-level; mission/business process-level; system-level] supply chain risk management policy that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the supply chain risk management policy and the associated supply chain risk management controls; b. Designate an [Assignment: organization-defined official] to manage the development, documentation, and dissemination of the supply chain risk management policy and procedures; and c. Review and update the current supply chain risk management: 1. Policy [Assignment: organization-defined frequency] and following [Assignment: organization-defined events]; and 2. Procedures [Assignment: organization-defined frequency] and following [Assignment: organization-defined events].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-2', 'Supply Chain Risk Management', 'Supply Chain Risk Management Plan', 'a. Develop a plan for managing supply chain risks associated with the research and development, design, manufacturing, acquisition, delivery, integration, operations and maintenance, and disposal of the following systems, system components or system services: [Assignment: organization-defined systems, system components, or system services]; b. Review and update the supply chain risk management plan [Assignment: organization-defined frequency] or as required, to address threat, organizational or environmental changes; and c. Protect the supply chain risk management plan from unauthorized disclosure and modification.', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-3', 'Supply Chain Risk Management', 'Supply Chain Controls and Processes', 'a. Establish a process or processes to identify and address weaknesses or deficiencies in the supply chain elements and processes of [Assignment: organization-defined system or system component] in coordination with [Assignment: organization-defined supply chain personnel]; b. Employ the following controls to protect against supply chain risks to the system, system component, or system service and to limit the harm or consequences from supply chain-related events: [Assignment: organization-defined supply chain controls]; and c. Document the selected and implemented supply chain processes and controls in [Selection: security and privacy plans; supply chain risk management plan; [Assignment: organization-defined document] ].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-4', 'Supply Chain Risk Management', 'Provenance', 'Document, monitor, and maintain valid provenance of the following systems, system components, and associated data: [Assignment: organization-defined systems, system components, and associated data].', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SR-5', 'Supply Chain Risk Management', 'Acquisition Strategies, Tools, and Methods', 'Employ the following acquisition strategies, contract tools, and procurement methods to protect against, identify, and mitigate supply chain risks: [Assignment: organization-defined acquisition strategies, contract tools, and procurement methods].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-6', 'Supply Chain Risk Management', 'Supplier Assessments and Reviews', 'Assess and review the supply chain-related risks associated with suppliers or contractors and the system, system component, or system service they provide [Assignment: organization-defined frequency].', 'Govern', 'GV.SC', 'Required for Moderate, High baselines', 2, true),
  ('SR-7', 'Supply Chain Risk Management', 'Supply Chain Operations Security', 'Employ the following Operations Security (OPSEC) controls to protect supply chain-related information for the system, system component, or system service: [Assignment: organization-defined Operations Security (OPSEC) controls].', 'Govern', 'GV.SC', 'No baseline assignment', 5, true),
  ('SR-8', 'Supply Chain Risk Management', 'Notification Agreements', 'Establish agreements and procedures with entities involved in the supply chain for the system, system component, or system service for the [Selection (one or more): notification of supply chain compromises; results of assessments or audits; [Assignment: organization-defined information] ].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-9', 'Supply Chain Risk Management', 'Tamper Resistance and Detection', 'Implement a tamper protection program for the system, system component, or system service.', 'Govern', 'GV.SC', 'Required for High baseline', 3, true),
  ('SR-10', 'Supply Chain Risk Management', 'Inspection of Systems or Components', 'Inspect the following systems or system components [Selection (one or more): at random; at [Assignment: organization-defined frequency], upon [Assignment: organization-defined indications of need for inspection] ] to detect tampering: [Assignment: organization-defined systems or system components].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-11', 'Supply Chain Risk Management', 'Component Authenticity', 'a. Develop and implement anti-counterfeit policy and procedures that include the means to detect and prevent counterfeit components from entering the system; and b. Report counterfeit system components to [Selection (one or more): source of counterfeit component; [Assignment: organization-defined external reporting organizations] ; [Assignment: organization-defined personnel or roles] ].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true),
  ('SR-12', 'Supply Chain Risk Management', 'Component Disposal', 'Dispose of [Assignment: organization-defined data, documentation, tools, or system components] using the following techniques and methods: [Assignment: organization-defined techniques and methods].', 'Govern', 'GV.SC', 'Required for Low, Moderate, High baselines', 1, true);

COMMIT;
